window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q18"]=window.__LIBQ["tien-nghich"]["q18"]||{};window.__LIBQ["tien-nghich"]["q18"]["techniques"]={"updatedAt":"2026-07-15","count":84,"techniques":[{"id":"ban-nguyen-ngung-tan","name":"Bản nguyên ngưng tán","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Bản nguyên","soHuu":["Vương Lâm"],"blurb":"Thần thông bản nguyên được Vương Lâm dốc sức thi triển trong đợt truy kích thứ tư của Đạo Ma Tông.","detail":"Khi Hồn Khải trên người sắp tan hết, Vương Lâm dùng Bản nguyên ngưng tán cùng Thất Thải Thương, Âm Nguyệt Hữu Tình và Lưu Nguyệt để sát thương đợt tu sĩ thứ tư, góp phần khiến làn sóng này gần như toàn diệt.","thuocTinh":"Bản nguyên","uyLuc":"Bùng phát bản nguyên trong hỗn chiến để sát thương số đông truy binh.","dacDiem":"Được dùng trong giai đoạn Vương Lâm đã bị tiêu hao nặng.","congNang":["Bạo phát bản nguyên phối hợp nhiều thần thông khác để đánh đợt truy kích thứ tư @c1794"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1794","tangDatToi":"thi triển trong chiến đấu","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1794","loai":"thi triển","importance":"normal","giaiDoan":"Đánh tan đợt thứ tư","text":"Vương Lâm thi triển Bản nguyên ngưng tán trong loạt thần thông cuối trước khi Hồn Khải tan hết.","anchor":"Bản nguyên ngưng tán!"}]},"capNhatToi":"@c1794","nguon":["@c1794"]},{"id":"hoa-ban-nguyen-chan-than","name":"Hỏa bản nguyên chân thân","cn":"","loai":"than-thong","loaiLabel":"Chân thân bản nguyên","phamCap":"không rõ","hePhai":"Bản nguyên","soHuu":["Vương Lâm"],"blurb":"Chân thân bản nguyên hỏa hiện ra sau lưng Vương Lâm, khuếch tán ra tám hướng để triển khai Hư Hỏa.","detail":"Trong vòng vây cuối trước khi bước sang Mạnh Thổ Châu, Vương Lâm gọi hỏa bản nguyên chân thân hiện ra sau lưng, dùng nó làm nền để Hư Hỏa thiêu đốt suy nghĩ trong nội tâm đám tu sĩ chặn đường.","thuocTinh":"Hỏa bản nguyên","uyLuc":"Khuếch tán lực hỏa bản nguyên để dẫn phát Hư Hỏa trên diện rộng.","dacDiem":"Gắn trực tiếp với việc thi triển Hư Hỏa trong chiến đấu.","congNang":["Triển khai lực hỏa bản nguyên để dẫn động Hư Hỏa thiêu đốt địch nhân @c1794"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1794","tangDatToi":"thi triển trong chiến đấu","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1794","loai":"thi triển","importance":"normal","giaiDoan":"Mở đường cuối cùng","text":"Vương Lâm gọi hỏa bản nguyên chân thân hiện ra phía sau để chuẩn bị dùng Hư Hỏa phá vòng vây.","anchor":"Chỉ thấy phía sau hắn, hỏa bản nguyên chân thân bất ngờ biến ảo ra"}]},"capNhatToi":"@c1794","nguon":["@c1794"]},{"id":"than-thong-dao-ma-doi-nui","name":"Thần thông Đạo Ma dời núi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đạo Ma Tông","soHuu":["Tông chủ Đạo Ma Tông"],"blurb":"Thần thông Đạo Ma dời núi là thuật Tông chủ Đạo Ma Tông dùng để huyễn hóa một đạo một ma và dời ranh giới địa vực. Trong chương này, nó nhổ bật dãy núi ngàn vạn dặm ở biên giới hai châu để chặn đường Vương Lâm.","detail":"Tông chủ Đạo Ma Tông gọi hai chữ Đạo, ma, khiến hai thân ảnh khổng lồ một đạo một ma hiện ra. Hai thân ảnh phối hợp nhổ bật dãy núi dài ngàn vạn dặm vốn là ranh giới Lục Ma Châu và Mạnh Thổ Châu, rồi ném nó vượt qua đầu Vương Lâm để khiến hắn vẫn bị tính là ở trong Lục Ma Châu.","thuocTinh":"Đạo ma","uyLuc":"Có thể nhổ bật và dời dãy núi biên giới dài ngàn vạn dặm.","congNang":["Dời ranh giới địa vực bằng cách nhổ bật dãy núi biên giới @c1795"],"nguoiTu":[{"ten":"Tông chủ Đạo Ma Tông","tuChuong":"@c1795","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1795","loai":"thi triển","importance":"normal","giaiDoan":"Dời ranh giới hai châu","text":"Tông chủ Đạo Ma Tông thi triển thần thông Đạo Ma để nhổ bật dãy núi biên giới và ném tới trước mặt Vương Lâm, cắt đường thoát của hắn.","anchor":"dãy núi dài cả ngàn vạn dặm bất ngờ bị một luồng lực lượng nhổ bật lên khỏi mặt đất"}]},"capNhatToi":"@c1795","nguon":["@c1795"]},{"id":"tuyet-hoc-thu-an-dao-ma-tong","name":"Tuyệt học thủ ấn Đạo Ma Tông","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông / thủ ấn","phamCap":"Không rõ","hePhai":"Đạo Ma Tông","soHuu":["Tông chủ Đạo Ma Tông"],"blurb":"Tuyệt học thủ ấn Đạo Ma Tông là thủ ấn mà Tông chủ Đạo Ma Tông dùng để trấn áp Vương Lâm. Thủ ấn này mượn hai hóa thân đạo — ma để tạo ra tiên ma ấn.","detail":"Tông chủ Đạo Ma Tông tuyên bố sẽ cho Vương Lâm biết uy lực tuyệt học thủ ấn của Đạo Ma Tông. Lão già đạo bào trắng và thanh niên hắc bào lần lượt hóa thành chưởng ấn trắng đen, rồi dung hợp thành tiên ma ấn.","thuocTinh":"Đạo ma","congNang":["Triệu đạo ảnh và ma ảnh hóa thành hai chưởng ấn để dung hợp thành tiên ma ấn @c1795"],"nguoiTu":[{"ten":"Tông chủ Đạo Ma Tông","tuChuong":"@c1795","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1795","loai":"thi triển","importance":"normal","giaiDoan":"Tạo tiên ma ấn","text":"Tông chủ Đạo Ma Tông thi triển tuyệt học thủ ấn, khiến hai hóa thân đạo — ma hóa thành chưởng ấn trắng đen nhằm trấn áp Vương Lâm.","anchor":"ta sẽ cho ngươi biết uy lực của tuyệt học thủ ấn của Đạo Ma Tông ta"}]},"capNhatToi":"@c1795","nguon":["@c1795"]},{"id":"tien-ma-an","name":"Tiên ma ấn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông / chưởng ấn","phamCap":"Không rõ","hePhai":"Đạo Ma Tông","soHuu":["Tông chủ Đạo Ma Tông"],"blurb":"Tiên ma ấn là ấn đen trắng do hai chưởng ấn đạo — ma dung hợp. Nó giáng xuống Vương Lâm với uy thế làm thiên địa ngày đêm điên đảo.","detail":"Hai chưởng ấn trắng và đen do đạo ảnh và ma ảnh hóa thành dung hợp phía trên Vương Lâm, tạo thành một tiên ma ấn khổng lồ lóe ánh sáng đen trắng. Tông chủ Đạo Ma Tông dùng nó để trấn áp Vương Lâm, nhưng sau đó đổi ý không giết mà bắt sống.","thuocTinh":"Tiên ma, đen trắng","uyLuc":"Khi hình thành khiến thiên địa xuất hiện cảnh ngày đêm điên đảo.","congNang":["Dung hợp hai chưởng ấn đạo — ma thành một ấn đen trắng để trấn áp đối thủ @c1795"],"nguoiTu":[{"ten":"Tông chủ Đạo Ma Tông","tuChuong":"@c1795","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1795","loai":"thi triển","importance":"normal","giaiDoan":"Trấn áp Vương Lâm","text":"Hai chưởng ấn đen trắng dung hợp thành tiên ma ấn giáng xuống Vương Lâm, buộc hắn đối diện kiếp nạn sinh tử.","anchor":"hóa thành một tiên ma ấn lóe lên ánh sáng đen trắng"}]},"capNhatToi":"@c1795","nguon":["@c1795"]},{"id":"ma-dao-gieo-ma-bien","name":"Ma đạo gieo ma biến","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông ma đạo","phamCap":"không rõ","hePhai":"Đạo Ma Tông","soHuu":["Tông chủ Đạo Ma Tông"],"blurb":"Ma đạo gieo ma biến là thủ đoạn Tông chủ Đạo Ma Tông dùng để phá tâm thần và ký ức của Vương Lâm theo yêu cầu của Tế Tự Lục Ma Hạt Miếu.","detail":"Tông chủ Đạo Ma Tông đồng ý toàn lực thi triển thủ đoạn này sau khi Tế Tự yêu cầu xóa thần trí và ký ức của Vương Lâm. Tác dụng được nêu là gieo ma để khiến mục tiêu tự phá hủy tâm thần.","thuocTinh":"ma đạo","uyLuc":"Có thể nhắm vào tâm thần, ký ức và thần trí của mục tiêu khi phối hợp thủ đoạn bản nguyên của người thi triển.","dacDiem":"Được dùng trong kế hoạch biến Vương Lâm thành vật trấn áp khí vận Lục Ma Châu.","congNang":["Gieo ma để phá hủy tâm thần, ký ức và thần trí của mục tiêu @c1796"],"nguoiTu":[{"ten":"Tông chủ Đạo Ma Tông","tuChuong":"@c1796","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1796","loai":"thi triển","importance":"normal","giaiDoan":"Dùng lên Vương Lâm","text":"Tông chủ Đạo Ma Tông nhận lời Tế Tự, dùng ma đạo gieo ma biến để phá tâm thần Vương Lâm.","anchor":"Tốt, Tế Tự đã nói như vậy thì bổn tông tất nhiên toàn lực lấy ma đạo gieo ma biến"}]},"dinhDanh":"goc","capNhatToi":"@c1796","nguon":["@c1796"]},{"id":"loi-ban-nguyen-lam-cau-noi","name":"Lôi bản nguyên làm cầu nối","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Thủ đoạn bản nguyên","phamCap":"không rõ","hePhai":"Đạo Ma Tông","soHuu":["Tông chủ Đạo Ma Tông"],"blurb":"Lôi bản nguyên làm cầu nối là thủ đoạn Tông chủ Đạo Ma Tông dùng để đưa ý chí xâm nhập vào Vương Lâm thông qua bản nguyên tương thông.","detail":"Tông chủ Đạo Ma Tông lợi dụng lôi bản nguyên đại thành của mình và lôi bản nguyên trong cơ thể Vương Lâm để dựng một thông đạo vô hình. Mục tiêu của thủ đoạn là thay thế, xóa bỏ tâm thần và ký ức của Vương Lâm từ bên trong.","thuocTinh":"lôi bản nguyên","uyLuc":"Có thể truyền lôi bản nguyên và ý chí ngoại lai vào cơ thể mục tiêu qua sự tương thông bản nguyên.","dacDiem":"Trong chương này bị Thiên Nghịch phá ngầm, khiến lực lượng truyền vào lại làm Vương Lâm mạnh lên.","congNang":["Đưa ý chí qua lôi bản nguyên tương thông để phá hủy tâm thần và ký ức mục tiêu @c1796"],"nguoiTu":[{"ten":"Tông chủ Đạo Ma Tông","tuChuong":"@c1796","tangDatToi":"đang thi triển","trangThai":"bị phá ngầm"}],"tabs":{"tienTrinh":[{"chuong":"@c1796","loai":"thi triển","importance":"normal","giaiDoan":"Xâm nhập Vương Lâm","text":"Tông chủ Đạo Ma Tông dùng lôi bản nguyên làm cầu nối để phá tâm thần và ký ức Vương Lâm, nhưng không thể hoàn chỉnh ngưng tụ ý chí trong cơ thể hắn.","anchor":"Ta lợi dùng lôi bản nguyên làm cầu nối, phá hủy tâm thần và ký ức của hắn"}]},"dinhDanh":"goc","capNhatToi":"@c1796","nguon":["@c1796"]},{"id":"thien-nghich-trong-linh-hon-vuong-lam","name":"Thiên Nghịch trong linh hồn Vương Lâm","cn":"","aliases":["Hạt châu trong linh hồn Vương Lâm"],"loai":"khac","loaiLabel":"Bảo hộ linh hồn","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thiên Nghịch trong linh hồn Vương Lâm âm thầm bảo vệ linh hồn và tâm thần của hắn khi bị trấn áp trong Lục Ma Hạt Miếu.","detail":"Trong lúc Vương Lâm hôn mê trong không gian màu lục, hạt châu trong linh hồn chậm rãi xoay chuyển, phát ra ánh sáng nhu hòa bảo vệ linh hồn và tâm thần. Nó còn hấp thu từng chút ý chí không thuộc về Vương Lâm, khiến kế hoạch của Tông chủ Đạo Ma Tông không thể hoàn thành.","thuocTinh":"bảo hộ linh hồn","uyLuc":"Bảo vệ linh hồn và hấp thu ý chí ngoại lai ngay cả khi chủ nhân hôn mê.","dacDiem":"Không bị Tế Tự và Tông chủ Đạo Ma Tông phát hiện trong quá trình phá tâm thần Vương Lâm.","congNang":["Bảo vệ linh hồn và tâm thần của Vương Lâm @c1796","Hấp thu từng chút ý chí ngoại lai xâm nhập qua lôi bản nguyên @c1796"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1796","tangDatToi":"không rõ","trangThai":"đang được bảo hộ"}],"tabs":{"tienTrinh":[{"chuong":"@c1796","loai":"xuất hiện","importance":"normal","giaiDoan":"Bảo hộ trong linh hồn","text":"Thiên Nghịch xoay chuyển trong linh hồn Vương Lâm, vừa bảo vệ hắn vừa hấp thu ý chí của Tông chủ Đạo Ma Tông.","anchor":"trong linh hồn Vương Lâm đang có một hạt châu chầm chậm xoay chuyển"}]},"dinhDanh":"bien-the","capNhatToi":"@c1796","nguon":["@c1796"]},{"id":"loi-dinh-chan-than","name":"Lôi đình chân thân","cn":"","aliases":["Lôi đình bản nguyên chân thân","Lôi đình chân thân","Lôi bản nguyên chân thân"],"loai":"than-thong","loaiLabel":"Bản nguyên chân thân","phamCap":"bản nguyên chân thân","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Lôi đình chân thân là hình thái chân thân do lôi bản nguyên của Vương Lâm ngưng tụ khi lượng lôi lực trong cơ thể bạo tăng tại Lục Ma Hạt Miếu. Tính đến thời điểm ghi nhận, chân thân này mới xuất hiện dấu hiệu hình thành và từng bị ý chí Tông chủ Đạo Ma Tông thao túng để trấn áp Vương Lâm, nhưng sau khi ý chí ngoại lai bị xóa bỏ, nó trở thành thứ Vương Lâm có thể chủ động đoạt lấy.","detail":"Sau khi Tông chủ Đạo Ma Tông liên tục truyền lôi bản nguyên vào cơ thể Vương Lâm và nuốt Lôi Đế Châu, lượng lôi lực chưa kịp lưu lại trong người tông chủ đã theo thông đạo tràn sang Vương Lâm. Nhờ vậy lôi bản nguyên trong cơ thể hắn tăng mạnh và bắt đầu ngưng tụ thành lôi đình chân thân. Khi chân thân cử động, nó trấn áp Vương Lâm rồi hóa thành vô số tia chớp nhập thể dưới sự thao túng của ý chí tông chủ. Sau khi ý chí ngoại lai bị xóa sạch, chân thân không còn bị khống chế và trở thành cơ hội để Vương Lâm chủ động nắm giữ. Tuy nhiên, tại mốc cuối cùng được ghi nhận, lôi đình chân thân vẫn chưa hoàn toàn thành hình.","thuocTinh":"lôi bản nguyên","uyLuc":"Là bước tiến trực tiếp của lôi bản nguyên Vương Lâm trong quá trình bị trấn áp, có thể trấn áp chủ thể và cưỡng chế nhập thể.","dacDiem":"Mới xuất hiện dấu hiệu ngưng tụ ở cuối tiến trình, chưa hoàn toàn thành hình; từng bị ý chí ngoại lai thao túng trước khi Vương Lâm có cơ hội tự mình nắm giữ.","congNang":["Ngưng tụ lôi bản nguyên thành chân thân khi lôi lực trong cơ thể tăng mạnh @c1796","Có khả năng trấn áp chủ thể và hóa thành vô số tia chớp nhập thể @c1798","Sau khi ý chí ngoại lai bị xóa, chân thân trở thành thứ chủ thể có thể chủ động đoạt lấy @c1798"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1796","tangDatToi":"Chưa chủ động nắm giữ","trangThai":"Chân thân đã nhập thể, chờ đoạt lại"}],"tabs":{"tienTrinh":[{"chuong":"@c1796","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Dấu hiệu ngưng tụ","text":"Lôi bản nguyên trong cơ thể Vương Lâm bạo tăng và xuất hiện dấu hiệu ngưng tụ lôi đình chân thân.","anchor":"Lôi bản nguyên trong cơ thể hắn trong tích tắc này ầm ầm tăng mạnh"},{"chuong":"@c1798","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhập thể và bị xóa ý chí","text":"Lôi đình bản nguyên chân thân cử động, trấn áp Vương Lâm rồi hóa thành vô số tia chớp nhập vào cơ thể hắn. Về sau giọt máu màu lục của Tế Tự xóa sạch ý chí của Tông chủ Đạo Ma Tông trong chân thân.","anchor":"lôi đình bản nguyên chân thân này bỗng cử động"}]},"dinhDanh":"goc","capNhatToi":"@c1796","nguon":["@c1796","@c1798"],"trangThai":"Ý chí ngoại lai đã bị xóa"},{"id":"loi-dinh-ban-nguyen","name":"Lôi đình bản nguyên","cn":"","loai":"khac","loaiLabel":"Bản nguyên lực","phamCap":"Không rõ","hePhai":"Lôi đình","soHuu":["Tông chủ Đạo Ma Tông","Vương Lâm"],"blurb":"Lôi đình bản nguyên được Tông chủ Đạo Ma Tông tán hết khỏi thân mình và truyền vào cơ thể Vương Lâm. Nguồn lực này thúc đẩy lôi uy quanh Vương Lâm tăng vọt và góp phần hình thành lôi đình bản nguyên chân thân.","detail":"Trong chương này, Tông chủ Đạo Ma Tông nuốt Lôi Đế Châu rồi phóng toàn bộ lôi đình bản nguyên cùng ý chí bản nguyên của mình qua thông đạo vô hình vào thân Vương Lâm. Lôi đình bản nguyên khiến khu vực quanh Vương Lâm hóa thành địa ngục sấm sét và trở thành lực lượng chủ chốt để ấn ký tia chớp trong mắt phải hắn sinh ra chân thân lôi đình.","congNang":["Có thể truyền cùng ý chí bản nguyên qua thông đạo vô hình vào thân người khác để thúc đẩy lôi uy và ngưng tụ chân thân lôi đình."],"tabs":{"tienTrinh":[{"chuong":"@c1797","loai":"thi triển","importance":"normal","giaiDoan":"Tán hết bản nguyên","text":"Tông chủ Đạo Ma Tông tán hết lôi đình bản nguyên trong thân và truyền vào cơ thể Vương Lâm.","anchor":"Lôi đình bản nguyên, tán hết"}]},"capNhatToi":"@c1797","nguon":["@c1797"]},{"id":"luc-ma-dai-tran","name":"Lục Ma đại trận","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Lục Ma Hạt Miếu","soHuu":["Tế Tự Lục Ma Hạt Miếu"],"blurb":"Lục Ma đại trận là trận pháp được Tế Tự hô mở trong màn thăm dò cực hạn đối với Vương Lâm.","detail":"Tế Tự ra lệnh mở Lục Ma đại trận khi giả như muốn giết Vương Lâm, mục đích là tạo áp lực sinh tử để thử xem tâm thần hắn còn tồn tại hay không. Chương này chưa mô tả đầy đủ hình thái vận chuyển của đại trận.","dinhDanh":"goc","thuocTinh":"Lục Ma","trangThai":"Được hô mở trong màn thăm dò","capNhatToi":"@c1798","congNang":["Dùng để phong tỏa và ngăn Vương Lâm chạy thoát theo lệnh Tế Tự @c1798"],"tabs":{"tienTrinh":[{"chuong":"@c1798","loai":"xuất hiện","importance":"normal","giaiDoan":"Lệnh mở trận","text":"Tế Tự hô mở Lục Ma đại trận trong lúc ra lệnh giết Vương Lâm, dùng nó như một phần của màn thăm dò sinh tử.","anchor":"mở Lục Ma đại trận ra, quyết không cho hắn chạy thoát"}]},"nguon":["@c1798"]},{"id":"than-thong-bo-cap-cua-luc-ma-su-gia","name":"Thần thông bọ cạp của Lục Ma sứ giả","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lục Ma Hạt Miếu","soHuu":["Hai Lục Ma sứ giả"],"blurb":"Thần thông bọ cạp của Lục Ma sứ giả là hợp kích do hai sứ giả Không Kiếp trung kỳ thi triển.","detail":"Khi Tế Tự ra lệnh giết Vương Lâm, hai Lục Ma sứ giả cùng thi triển tu vi, hóa thần thông thành hai con bọ cạp lớn lao thẳng vào thân thể Vương Lâm. Công kích này bị tầng sóng gợn màu lục quanh Vương Lâm triệt tiêu và bắn ngược.","dinhDanh":"goc","thuocTinh":"Lục Ma","trangThai":"Đã thi triển","capNhatToi":"@c1798","congNang":["Hóa thành hai con bọ cạp lớn để hợp kích mục tiêu @c1798"],"uyLuc":"Do hai tu sĩ Không Kiếp trung kỳ cùng ra tay trong khoảng cách gần.","tabs":{"tienTrinh":[{"chuong":"@c1798","loai":"thi triển","importance":"normal","giaiDoan":"Hợp kích thăm dò","text":"Hai Lục Ma sứ giả thi triển thần thông, hóa thành hai con bọ cạp lớn lao tới Vương Lâm theo lệnh của Tế Tự.","anchor":"hóa thành hai con bọ cạp thật lớn mang theo tiếng gầm thét dữ tợn"}]},"nguon":["@c1798"]},{"id":"tho-ban-nguyen","name":"Thổ bản nguyên","cn":"","loai":"khac","loaiLabel":"Bản nguyên","phamCap":"Bản nguyên","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thổ bản nguyên là bản nguyên thứ chín trong cơ thể Vương Lâm, được ngưng tụ thành công nhờ Mạnh Thổ Châu và ba hạt cát thổ bản nguyên thúc đẩy.","detail":"Tại Lục Ma Hạt Miếu, Tế Tự Lục Ma Hạt Miếu dùng ba khối Mạnh Thổ Châu khiến thổ bản nguyên trong cơ thể Vương Lâm có chút thành tựu, sau đó tiếp tục dùng ba hạt cát thổ bản nguyên. Thổ bản nguyên lực tuần hoàn chín lần, kết quả là bản nguyên thứ chín xuất hiện trong cơ thể Vương Lâm.","thuocTinh":"Thổ","trangThai":"Đã xuất hiện trong cơ thể Vương Lâm","capNhatToi":"@c1800","congNang":["Hỗ trợ Vương Lâm ngưng tụ bản nguyên thứ chín @c1800"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1800","tangDatToi":"Bản nguyên thứ chín xuất hiện","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1800","loai":"xuất hiện","importance":"major","giaiDoan":"Bản nguyên thứ chín","text":"Thổ bản nguyên được Mạnh Thổ Châu và ba hạt cát thổ bản nguyên thúc đẩy, khiến trong cơ thể Vương Lâm xuất hiện bản nguyên thứ chín.","anchor":"Trong cơ thể hắn bất ngờ xuất hiện bản nguyên thứ chín"}]},"nguon":["@c1800"]},{"id":"tho-ban-nguyen-chan-than","name":"Thổ bản nguyên chân thân","cn":"","loai":"khac","loaiLabel":"Bản nguyên chân thân","phamCap":"Bản nguyên chân thân","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thổ bản nguyên chân thân là bản nguyên chân thân thứ ba xuất hiện trong cơ thể Vương Lâm, hình thành sau khi hấp thu hạt cát thổ bản nguyên thứ ba, tạo nền tảng để Nguyên Thần của hắn sở hữu ba bản nguyên chân thân khi rời Thiên Nghịch Châu.","detail":"Sau khi hạt cát thổ bản nguyên thứ ba dung nhập vào cơ thể, thổ bản nguyên lực trong người Vương Lâm tăng mạnh, thương thế nghịch chuyển và dấu hiệu bản nguyên chân thân thứ ba xuất hiện. Tuy nhiên chân thân này chưa hoàn toàn ngưng tụ do ý chí của Vương Lâm chưa thực sự dung nhập. Đây là một trong baản nguyên chân thân mà Nguyên Thần Vương Lâm mang theo khi rời Thiên Nghịch Châu.","thuocTinh":"Thổ","trangThai":"Có dấu hiệu ngưng tụ, chưa hoàn toàn thành hình","capNhatToi":"@c1800","congNang":["Tạo nền tảng cho Vương Lâm sở hữu ba bản nguyên chân thân khi Nguyên Thần rời Thiên Nghịch Châu @c1800"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1800","tangDatToi":"Dấu hiệu chân thân thứ ba","trangThai":"chưa hoàn toàn ngưng tụ"}],"tabs":{"tienTrinh":[{"chuong":"@c1800","loai":"xuất hiện","importance":"major","giaiDoan":"Dấu hiệu chân thân thứ ba","text":"Sau hạt cát thứ ba, cơ thể Vương Lâm xuất hiện dấu hiệu thổ bản nguyên chân thân nhưng chưa hoàn toàn ngưng tụ vì ý chí chưa dung nhập.","anchor":"Trong cơ thể Vương Lâm bất ngờ xuất hiện dấu hiệu của bản nguyên chân thân thứ ba"}]},"nguon":["@c1800"],"dacDiem":"Hình thành từ hạt cát thổ bản nguyên thứ ba; tại thời điểm xuất hiện chưa hoàn toàn ngưng tụ vì ý chí Vương Lâm chưa dung nhập."},{"id":"tien-co-dong-the","name":"Tiên cổ đồng thể","cn":"","loai":"than-thong","loaiLabel":"Trạng thái thân thể","phamCap":"Chưa rõ","hePhai":"Cổ Tộc và Tiên Tộc","soHuu":["Vương Lâm"],"blurb":"Tiên cổ đồng thể là trạng thái thân thể do Tế Tự Lục Ma Hạt Miếu tạo ra trên thân Vương Lâm, cho phép đồng thời dung nạp và vận hành cả hệ thống tiên lực lẫn thần thông Cổ Tộc.","detail":"Tế Tự Lục Ma Hạt Miếu đề xuất khả năng đưa thân thể Vương Lâm đạt trạng thái tiên cổ đồng thể. Do huyết mạch Cổ Tộc vốn bài xích tiên lực, cần khai thông thêm một hệ kinh mạch thứ hai để hai nguồn lực cùng tồn tại mà không xung đột. Khi Nguyên Thần Vương Lâm rời Thiên Nghịch và điều khiển thân thể này, trạng thái tiên cổ đồng thể sẽ đặt nền cho việc hắn đồng thời thi triển thần thông của cả Cổ Tộc và Tiên Tộc.","thuocTinh":"Tiên lực và thân thể Cổ Tộc","uyLuc":"Có thể đặt nền cho việc đồng thời thi triển thần thông Cổ Tộc và Tiên Tộc.","dacDiem":"Cần kinh mạch thứ hai để thân thể Cổ Tộc không bài xích tiên lực.","congNang":["Giúp thân thể Vương Lâm có khả năng đồng thời dung nạp và thi triển thần thông Cổ Tộc cùng Tiên Tộc @c1801"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1801","tangDatToi":"Thân thể được cải tạo theo trạng thái tiên cổ đồng thể","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1801","loai":"xuất hiện","importance":"major","giaiDoan":"Xác lập trạng thái","text":"Tế Tự Lục Ma Hạt Miếu nêu khả năng tạo tiên cổ đồng thể trên thân thể Vương Lâm và khai kinh mạch để dung nạp tiên lực.","anchor":"Ta tuy có thể làm cho hắn có được tiên cổ đồng thể"}]},"capNhatToi":"@c1801","nguon":["@c1801"]},{"id":"kinh-mach-thu-hai-trong-than-the-vuong-lam","name":"Kinh mạch thứ hai trong thân thể Vương Lâm","cn":"","loai":"khac","loaiLabel":"Cấu trúc tu luyện thân thể","phamCap":"Chưa rõ","hePhai":"Tiên lực trong thân thể Cổ Tộc","soHuu":["Vương Lâm"],"blurb":"Kinh mạch thứ hai làệ thống tuần hoàn bổ sung được khai mở bên trong thân thể Vương Lâm, hình thành từ nhiều vật liệu trân quý cùng một sợi tóc Tiên Tổ, cho phép tiên lực vận hành trong cơ thể vốn mang huyết mạch Cổ Tộc.","detail":"Kinh mạch thứ hai hình thành khi bốn lá cây, sáu đan dược, sáu sợi tơ máu và ba viên đá xám được Tế Tự Lục Ma Hạt Miếu đưa vào thân thể Vương Lâm. Sợi tóc Tiên Tổ dung hợp với huyết nhục, hoàn thành vòng tuần hoàn mới. Hệ kinh mạch này giải quyết mâu thuẫn giữa thân xác Cổ Tộc và tiên lực, tạo đường dẫn để thân thể phát huy cơ duyên tiên cổ đồng thể khi Nguyên Thần Vương Lâm trở lại điều khiển.","thuocTinh":"Khai thông tiên lực","uyLuc":"Cho phép thân thể Vương Lâm phát huy cơ duyên tiên cổ đồng thể khi Nguyên Thần trở lại điều khiển.","dacDiem":"Được tạo bằng nhiều vật liệu cực quý và một sợi tóc Tiên Tổ.","congNang":["Tạo vòng tuần hoàn mới để tiên lực vận hành trong thân thể vốn mang huyết mạch Cổ Tộc @c1801"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1801","tangDatToi":"Kinh mạch thứ hai hình thành","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1801","loai":"xuất hiện","importance":"major","giaiDoan":"Khai mạch","text":"Kinh mạch thứ hai xuất hiện trong cơ thể Vương Lâm sau khi các vật liệu dung hợp và tạo thành vòng tuần hoàn mới.","anchor":"Vào tích tắc này, trong cơ thể Vương Lâm xuất hiện kinh mạch thứ hai"}]},"capNhatToi":"@c1801","nguon":["@c1801"]},{"id":"thuy-ban-nguyen-chan-than","name":"Thủy bản nguyên chân thân","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Bản nguyên chân thân","phamCap":"Không rõ","hePhai":"Thủy bản nguyên","soHuu":["Vương Lâm"],"blurb":"Thủy bản nguyên chân thân là khối bản nguyên chân thân thứ tư hình thành trong cơ thể Vương Lâm, được ngưng tụ nhờ hàng loạt vật phẩm thủy bản nguyên cùng máu truyền thừa của Tế Tự Lục Ma Hạt Miếu. Khi thành hình, từ cơ thể Vương Lâm tuôn ra khí tức thủy bản nguyên kinh thiên.","detail":"Thủy bản nguyên chân thân được ngưng tụ khi thủy bản nguyên trong thân thể Vương Lâm tăng mạnh qua nhiều chí bảo: Tiên Tổ hồn mẫu, Phàm Mộng U Thủy, dung dịch đạo tâm, máu thủy tiên, thiên địa thủy nguyên và máu truyền thừa của lão già mặc lục bào thuộc Tế Tự Lục Ma Hạt Miếu. Trải qua mấy tháng ôn dưỡng, khối chân thân thứ tư chính thức thành hình. Chân thân này hiện vẫn ở trạng thái như ngủ say, nhưng chỉ cần ý niệm Vương Lâm chuyển động là có thể điều khiển. Đây là khối bản nguyên chân thân thuộc hệ thủy, xếp sau ba khối trước đó trong thân thể Vương Lâm.","thuocTinh":"Thủy bản nguyên","uyLuc":"Khi thành hình, từ cơ thể Vương Lâm tuôn ra khí tức thủy bản nguyên kinh thiên.","dacDiem":"Là khối bản nguyên chân thân thứ tư được tạo trong thân thể Vương Lâm, thuộc hệ thủy bản nguyên.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1802","tangDatToi":"Ngưng tụ thành hình","trangThai":"dang-tu"}],"congNang":["Ngưng tụ thành một khối bản nguyên chân thân thuộc thủy bản nguyên trong cơ thể Vương Lâm @c1802"],"tabs":{"tienTrinh":[{"chuong":"@c1802","loai":"xuất hiện","importance":"major","giaiDoan":"Ngưng tụ thành hình","text":"Thủy bản nguyên trong cơ thể Vương Lâm được thúc đẩy bởi nhiều chí bảo và máu truyền thừa, sau mấy tháng hình thành thủy bản nguyên chân thân.","anchor":"từ cơ thể Vương Lâm tuôn ra một luồng khí tức thủy bản nguyên kinh thiên"}]},"capNhatToi":"@c1802","nguon":["@c1802"]},{"id":"thien-dia-luc-cua-luc-ma-hat","name":"Thiên địa lực của Lục Ma Hạt","cn":"","aliases":[],"loai":"khac","loaiLabel":"Thiên địa lực","phamCap":"Không rõ","hePhai":"Lục Ma Hạt","soHuu":["Lục Ma Hạt","Vương Lâm"],"blurb":"Lực lượng theo lục khí từ Lục Ma Lô dung nhập thân thể Vương Lâm, không thuộc Cổ Tộc hay Tiên Tộc mà thuộc Lục Ma Hạt và cũng thuộc về Vương Lâm.","detail":"Thiên địa lực này được lục khí trong Lục Ma Lô đưa vào thân thể Vương Lâm trong quá trình luyện hóa. Nó là lực lượng tinh thuần dùng để cải tạo và tăng cường thân thể, được xác định không phải khí tức Cổ Tộc hay Tiên Tộc.","thuocTinh":"Thiên địa lực Lục Ma Hạt","uyLuc":"Có thể khiến tu vi Vương Lâm tăng vọt nếu hắn điều khiển thân thể hấp thu.","dacDiem":"Không thuộc Cổ Tộc hay Tiên Tộc, mà thuộc Lục Ma Hạt và cũng thuộc về Vương Lâm.","congNang":["Cải tạo và tăng cường thân thể Vương Lâm trong Lục Ma Lô @c1802","Có thể làm tu vi Vương Lâm tăng vọt nếu được hấp thu @c1802"],"tabs":{"tienTrinh":[{"chuong":"@c1802","loai":"xuất hiện","importance":"normal","giaiDoan":"Dung nhập thân thể","text":"Lục khí từ Lục Ma Lô mang thiên địa lực tinh thuần chui vào thân thể Vương Lâm trong lúc hắn vẫn nhẫn nại chưa hấp thu.","anchor":"Đây không phải là khí tức của Cổ Tộc, không phải là khí tức của Tiên Tộc"}]},"capNhatToi":"@c1802","nguon":["@c1802"]},{"id":"nghi-thuc-thuc-tinh-luc-ma-hat-hon","name":"Nghi thức thức tỉnh Lục Ma Hạt Hồn","cn":"","loai":"bi-thuat","loaiLabel":"Nghi thức","phamCap":"Không rõ","hePhai":"Lục Ma Hạt Miếu","soHuu":["Tế Tự Lục Ma Hạt Miếu"],"blurb":"Nghi thức do Tế Tự Lục Ma Hạt Miếu thi triển để gọi phân hồn Lục Ma Hạt thức tỉnh.","detail":"Lão già mặc lục bào dùng thân phận Tế Tự đời này, đọc chú ngữ cổ xưa khiến kiến trúc hình bọ cạp chấn động và chín luồng lục khí ngưng tụ thành hư ảnh bọ cạp màu lục.","thuocTinh":"chú ngữ, nghi thức triệu tỉnh","nguonGoc":"Tế Tự Lục Ma Hạt Miếu","uyLuc":"Có thể dẫn động phân hồn Lục Ma Hạt bị trấn áp dưới Lục Ma Châu hiện thân.","dacDiem":"Gắn với kiến trúc hình bọ cạp và thân phận Tế Tự đời này.","congNang":["Gọi phân hồn Lục Ma Hạt thức tỉnh trong @c1803"],"nguoiTu":[{"ten":"Tế Tự Lục Ma Hạt Miếu","tuChuong":"@c1803","tangDatToi":"Thi triển nghi thức thức tỉnh","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1803","loai":"xuất hiện","importance":"normal","giaiDoan":"Thức tỉnh phân hồn","text":"Tế Tự Lục Ma Hạt Miếu đọc chú ngữ cổ xưa, khiến kiến trúc bọ cạp rung chuyển và gọi Lục Ma Hạt Hồn hiện ra.","anchor":"Lời nói của lão già vừa dứt, trong miệng dần dần vang lên những chú ngữ cổ xưa"}]},"capNhatToi":"@c1803","nguon":["@c1803"]},{"id":"can-nuot-nguyen-than-hat-hon","name":"Cắn nuốt Nguyên Thần/Hạt Hồn","cn":"","loai":"bi-thuat","loaiLabel":"Hồn phách giao chiến","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm","Lục Ma Hạt"],"blurb":"Lối giao chiến trực tiếp giữa Nguyên Thần và Hạt Hồn trong thân thể, không dựa vào thần thông hay pháp thuật.","detail":"Trong thân thể Vương Lâm, hai bên chỉ cắn nuốt lẫn nhau. Vương Lâm chuẩn bị lâu dài nên dần chiếm thượng phong trước phân hồn Lục Ma Hạt suy yếu và thiếu phòng bị.","thuocTinh":"hồn phách, thôn phệ","uyLuc":"Có thể làm phân hồn Lục Ma Hạt suy yếu, sợ hãi và buộc phải rút khỏi thân thể Vương Lâm.","dacDiem":"Không dùng thần thông hay pháp thuật, chỉ là cắn nuốt trực diện giữa hai hồn thể.","congNang":["Thôn phệ phân hồn và Nguyên Thần đối địch trong @c1803"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1803","tangDatToi":"Dùng để phản nuốt Lục Ma Hạt Hồn","trangThai":"đã dùng"},{"ten":"Lục Ma Hạt","tuChuong":"@c1803","tangDatToi":"Phản kháng bằng cắn nuốt","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1803","loai":"thi triển","importance":"normal","giaiDoan":"Phản đoạt xá","text":"Vương Lâm và Lục Ma Hạt Hồn giao chiến bằng cách cắn nuốt trực tiếp trong thân thể, khiến phân hồn Lục Ma Hạt dần thất thế.","anchor":"Không có thần thông, không có pháp thuật, chỉ đơn giản là cắn nuốt"}]},"capNhatToi":"@c1803","nguon":["@c1803"]},{"id":"anh-mat-tran-ap-thien-dia","name":"Ánh mắt trấn áp thiên địa","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông uy áp","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ánh mắt mang uy nghiêm thiên địa, tạo cảm giác bị thiên địa pháp tắc trấn áp.","detail":"Vương Lâm dùng ánh mắt được lão già mặc lục bào ban cho để áp chế tâm thần đối phương. Uy áp này khiến Vân Dật Phong và Đường Giai chấn động, còn Biên Vân cảm nhận như trời cao hóa thành ánh mắt của Vương Lâm để trấn áp mình.","thuocTinh":"Uy áp, trấn áp tâm thần","uyLuc":"Có thể khiến tu sĩ từng giao chiến với Vương Lâm như Biên Vân lùi xa trong hoảng sợ.","dacDiem":"Cảm giác trấn áp giống thiên địa pháp tắc.","congNang":["Trấn áp tâm thần như thiên địa pháp tắc @c1804"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1804","tangDatToi":"Chưa rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1804","loai":"thi triển","importance":"normal","giaiDoan":"Trấn áp ba tu sĩ Thiên Ngưu Châu","text":"Vương Lâm dùng ánh mắt uy nghiêm khiến ba tu sĩ Thiên Ngưu Châu bị áp chế tâm thần, đặc biệt Biên Vân cảm nhận như trời cao trấn áp bản thân.","anchor":"Thậm chí hắn còn mơ hồ cảm nhận được, trời cao trấn áp bản thân chính là do ánh mắt của đối phương biến thành."}]},"capNhatToi":"@c1804","nguon":["@c1804"]},{"id":"am-dao-van-cot-cot-dao","name":"Âm đao vạn cốt / cốt đao","cn":"","aliases":["Âm đao vạn cốt","cốt đao"],"loai":"than-thong","loaiLabel":"Thần thông vũ khí hóa đao","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông hóa thành đao âm/cốt đao, được Vương Lâm và các bản nguyên chân thân dùng để chém hồn.","detail":"Trong Ma Hạt Miếu, Vương Lâm cùng bốn bản nguyên chân thân đồng loạt xuất đao, tạo thành năm đao kinh thiên. Đòn này khiến Lục Ma Hạt Hồn bị phân thành sáu phần.","uyLuc":"Ngũ đao phối hợp có thể phân hồn Lục Ma Hạt Hồn thành sáu phần.","dacDiem":"Có liên hệ với âm đao vạn cốt và cốt đao do Vương Lâm thi triển trong huyết nhục.","congNang":["Chém hồn phách thành nhiều phần khi phối hợp với bốn bản nguyên chân thân @c1804"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1804","tangDatToi":"Ngũ đao phối hợp bản thể và bốn chân thân","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1804","loai":"thi triển","importance":"normal","giaiDoan":"Ngũ đao phân hồn","text":"Vương Lâm cùng bốn bản nguyên chân thân chém ra năm đao, ép Lục Ma Hạt Hồn không thể tránh và bị chia thành sáu phần.","anchor":"Tổng cộng là năm đao kinh thiên!"}]},"capNhatToi":"@c1804","nguon":["@c1804"]},{"id":"bon-ban-nguyen-chan-than","name":"Bốn bản nguyên chân thân","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Chân thân bản nguyên","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bốn chân thân bản nguyên của Vương Lâm phối hợp với bản thể để xuất kích.","detail":"Bốn bản nguyên chân thân đứng sau Vương Lâm cùng chém ra bốn đao, hợp với một đao của bản thể thành thế năm đao. Sự phối hợp này khiến Lục Ma Hạt Hồn bị phân hồn.","thuocTinh":"Bản nguyên chân thân","congNang":["Phối hợp bản thể cùng xuất kích, tạo thế nhiều đòn đồng thời @c1804"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1804","tangDatToi":"Bốn chân thân đồng loạt xuất đao","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1804","loai":"thi triển","importance":"normal","giaiDoan":"Phối hợp chém Hạt Hồn","text":"Bốn bản nguyên chân thân phối hợp bản thể Vương Lâm xuất đao, tạo thành năm đao cùng chém xuống Lục Ma Hạt Hồn.","anchor":"cộng cả bốn đao của bốn bản nguyên chân thân phía sau Vương Lâm"}]},"capNhatToi":"@c1804","nguon":["@c1804"]},{"id":"chin-dao-ban-nguyen-cua-vuong-lam","name":"Chín đạo bản nguyên của Vương Lâm","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Hệ thống tu luyện","phamCap":"Không rõ","hePhai":"Bản nguyên của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Hệ thống chín đạo bản nguyên mà Vương Lâm đã có trong lúc bế quan ở Hạt Miếu. Chúng gồm sinh tử, nhân quả, chân giả, cấm chế, sát lục, lôi, hỏa, thủy và thổ.","detail":"Chín đạo bản nguyên này là nền tảng để Vương Lâm từ Không Linh đỉnh phong công kích Không Huyền. Chương này xác nhận bản nguyên thứ chín có vai trò then chốt khiến tu vi hắn tăng mạnh và mở ra mục tiêu quy nhất bản nguyên về sau.","thuocTinh":"Sinh tử, nhân quả, chân giả, cấm chế, sát lục, lôi, hỏa, thủy, thổ","nguonGoc":"Tích lũy tu luyện của Vương Lâm","congNang":["Làm nền tảng để Vương Lâm công kích Không Huyền @c1805","Là cơ sở để Vương Lâm tính chuyện quy nhất bản nguyên @c1805"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1805","tangDatToi":"Có đủ chín đạo bản nguyên","trangThai":"dang-tu"}],"capNhatToi":"@c1805","nguon":["@c1805"]},{"id":"tam-dai-ngu-hanh-ban-nguyen-dung-hop","name":"Tam đại ngũ hành bản nguyên dung hợp","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Dung hợp bản nguyên","phamCap":"Không rõ","hePhai":"Bản nguyên ngũ hành của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Phương pháp Vương Lâm dùng để hợp nhất thủy, hỏa và thổ bản nguyên. Thành quả là một tồn tại độc lập giống thiên địa ngũ hành phân thân.","detail":"Vương Lâm dùng thổ bản nguyên làm môi giới giữa thủy và hỏa, nhiều lần phun Nguyên Thần huyết để đưa ý chí bản thân vào quá trình dung hợp. Sau nhiều tháng và thêm bảy ngày va chạm liên tục, ba đạo bản nguyên hợp nhất, tạo ra chân thân mới ẩn chứa thủy, hỏa, thổ và kéo tu vi hắn lên Không Huyền trung kỳ.","thuocTinh":"Thủy, hỏa, thổ","nguonGoc":"Do Vương Lâm tự dung hợp trong lúc bế quan ở Hạt Miếu","yeuCau":"Cần có thủy, hỏa, thổ bản nguyên chân thân và dùng thổ làm môi giới","uyLuc":"Tạo một tồn tại độc lập giống thiên địa ngũ hành phân thân và thúc đẩy tu vi Vương Lâm tăng lên Không Huyền trung kỳ.","dacDiem":"Dung hợp ba đạo bản nguyên ngũ hành, trong đó thổ điều hòa thủy và hỏa.","congNang":["Tạo thiên địa ngũ hành phân thân chứa thủy, hỏa, thổ @c1805","Giúp tu vi Vương Lâm tăng tới Không Huyền trung kỳ @c1805"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1805","tangDatToi":"Dung hợp thành công thủy, hỏa, thổ","trangThai":"dang-tu"}],"capNhatToi":"@c1805","nguon":["@c1805"]},{"id":"loi-than-dung-sat-luc-va-cam-che","name":"Lôi thân dung sát lục và cấm chế","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Dung hợp bản nguyên","phamCap":"Không rõ","hePhai":"Bản nguyên của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Phương pháp Vương Lâm lấy lôi đình bản nguyên chân thân làm chính thể để hấp thu sát lục và cấm chế. Sau mấy tháng, lôi đình chân thân dung hợp thành công và bộc phát uy áp kinh thiên.","detail":"Ban đầu Vương Lâm định dùng lôi đình bản nguyên dẫn dắt sát lục và cấm chế nhưng thất bại vì sát lục bá đạo, cấm chế lại khó dung với lôi. Hắn đổi hướng, để lôi đình bản nguyên chân thân làm chính thể hấp thu hai đạo bản nguyên đặc thù, cuối cùng khiến lôi đình chân thân chứa ba đạo bản nguyên.","thuocTinh":"Lôi đình, sát lục, cấm chế","nguonGoc":"Do Vương Lâm đổi phương pháp dung hợp sau khi cách dùng lôi đình làm phụ trợ thất bại","yeuCau":"Cần lôi đình bản nguyên chân thân làm chính thể và có sát lục, cấm chế bản nguyên để hấp thu","uyLuc":"Khi dung hợp thành công, lôi đình bản nguyên chân thân bộc phát uy áp kinh thiên.","dacDiem":"Không dùng lôi đình làm phụ trợ mà biến lôi đình chân thân thành vật chứa chính cho hai đạo bản nguyên đặc thù.","congNang":["Khiến lôi đình bản nguyên chân thân dung hợp thêm sát lục và cấm chế @c1805","Tạo một chân thân chứa ba đạo bản nguyên @c1805"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1805","tangDatToi":"Dung hợp thành công sát lục và cấm chế vào lôi đình chân thân","trangThai":"dang-tu"}],"capNhatToi":"@c1805","nguon":["@c1805"]},{"id":"nguyen-than-huyet","name":"Nguyên Thần huyết","cn":"","aliases":["Huyết tinh Nguyên Thần"],"loai":"bi-thuat","loaiLabel":"Huyết tinh Nguyên Thần","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Huyết tinh Nguyên Thần mà Vương Lâm dùng trong quá trình dung hợp bản nguyên. Nó mang ý chí của hắn và giúp tăng khả năng hợp nhất các bản nguyên.","detail":"Trong chương này, Vương Lâm nhiều lần phun Nguyên Thần huyết tinh để đưa ý chí bản thân vào thủy, hỏa, thổ khi dung hợp tam đại bản nguyên. Sau đó hắn tiếp tục dùng huyết tinh bao phủ lôi đình bản nguyên chân thân trong quá trình hấp thu sát lục và cấm chế.","thuocTinh":"Nguyên Thần huyết tinh","nguonGoc":"Từ Nguyên Thần của Vương Lâm","congNang":["Đưa ý chí của Vương Lâm vào quá trình dung hợp bản nguyên @c1805","Tăng khả năng dung hợp giữa các bản nguyên @c1805"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1805","tangDatToi":"Dùng trong dung hợp thủy, hỏa, thổ và lôi đình với sát lục, cấm chế","trangThai":"dang-tu"}],"capNhatToi":"@c1805","nguon":["@c1805"]},{"id":"sat-luc-ban-nguyen","name":"Sát lục bản nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bản nguyên","phamCap":"Đặc thù","hePhai":"","soHuu":["Vương Lâm","Thanh Thủy"],"blurb":"Sát lục bản nguyên là một loại bản nguyên lực đặc thù, hình thành từ sát lục vô biên và tín niệm giết chóc. Khi dung nhập lôi đình bản nguyên chân thân của Vương Lâm, nó tạo thành sát lục lôi — một biến hóa hiếm thấy trong thiên địa.","detail":"Sát lục bản nguyên vốn vô hình vô ảnh, gắn liền với sát khí và ý chí giết chóc cực mạnh. Thanh Thủy từng sở hữu một đạo sát lục bản nguyên; Vương Lâm vô tình để nó dung nhập lôi đình bản nguyên chân thân, dẫn đến sự phát sinh biến hóa hiếm thấy trong thiên địa. Nó đóng vai trò nền tảng cho sát lục lôi khi kết hợp với lôi đình bản nguyên.","thuocTinh":"Sát lục","uyLuc":"Có thể làm nền cho sát lục lôi khi dung hợp với lôi đình bản nguyên.","dacDiem":"Cần sát lục vô biên và tín niệm giết chóc làm nền tảng.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1806","tangDatToi":"Dung nhập lôi đình bản nguyên chân thân","trangThai":"đang nắm giữ"},{"ten":"Thanh Thủy","tuChuong":"@c1806","tangDatToi":"Từng có một đạo sát lục bản nguyên","trangThai":"được nhắc tới"}],"congNang":["Dung nhập lôi đình bản nguyên chân thân để tạo thành sát lục lôi @c1806"],"tabs":{"tienTrinh":[{"chuong":"@c1806","loai":"xuất hiện","importance":"major","giaiDoan":"Dung nhập lôi đình","text":"Sát lục bản nguyên được giải thích là bản nguyên lực đặc thù, khi dung nhập lôi đình bản nguyên chân thân của Vương Lâm thì biến hóa thành sát lục lôi.","anchor":"Sát lục bản nguyên là một loại bản nguyên lực đặc thù, vốn vô hình vô ảnh"}]},"capNhatToi":"@c1806","nguon":["@c1806"]},{"id":"sat-luc-loi","name":"Sát lục lôi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Lôi đình bản nguyên biến dị","phamCap":"Diệt thế","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sát lục lôi là loại lôi sinh ra từ sự dung hợp giữa lôi đình bản nguyên chân thân và sát lục bản nguyên của Vương Lâm, mang uy lực diệt thế có thể gây hủy diệt vượt phạm vi một châu nếu bùng phát ngoài kiểm soát.","detail":"Tại chương 1806, trong chân thân Vương Lâm, lôi đình bản nguyên và sát lục bản nguyên dung hợp hình thành sát lục lôi. Đạo lôi này bị cấm chế bản nguyên của Vương Lâm hạn chế bên trong lôi đình bản nguyên chân thân, không thể tự do khuếch tán. Dù vậy, chỉ một tia khí tức thoáng tỏa ra từ Hạt Miếu đã đủ khiến sinh linh toàn Lục Ma Châu run rẩy, cho thấy mức uy hiếp khủng bố của nó. Chính Vương Lâm cũng kinh hãi trước loại lôi này.","thuocTinh":"Lôi đình, sát lục","uyLuc":"Có khả năng hủy diệt vượt quá phạm vi một châu nếu bùng phát ngoài kiểm soát.","dacDiem":"Bị cấm chế bản nguyên của Vương Lâm hạn chế trong lôi đình bản nguyên chân thân.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1806","tangDatToi":"Nắm giữ ngoài ý muốn","trangThai":"bị hạn chế trong chân thân"}],"congNang":["Mang uy lực diệt thế khi lôi đình bản nguyên và sát lục bản nguyên dung hợp @c1806","Khí tức thoáng tỏa ra đủ khiến sinh linh toàn Lục Ma Châu run rẩy @c1806"],"tabs":{"tienTrinh":[{"chuong":"@c1806","loai":"xuất hiện","importance":"major","giaiDoan":"Sinh ra trong chân thân","text":"Sát lục lôi hình thành từ sự dung hợp giữa lôi đình bản nguyên chân thân và sát lục bản nguyên của Vương Lâm, bộc lộ uy lực diệt thế và sau đó bị cấm chế bản nguyên hạn chế.","anchor":"Lôi và sát lục dung hợp. Tạo thành sát lục lôi"}]},"capNhatToi":"@c1806","nguon":["@c1806"]},{"id":"cam-che-ban-nguyen","name":"Cấm chế bản nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bản nguyên pháp tắc","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cấm chế bản nguyên là bản nguyên mang tính pháp tắc của Vương Lâm. Khi sát lục lôi bất ổn, nó dung hợp với lôi đình bản nguyên chân thân và hóa thành tấm lưới hạn chế đạo lôi này.","detail":"Trong chương 1806, cấm chế bản nguyên được mô tả là pháp tắc, sau khi dung hợp liền hóa thành tấm lưới lớn bao phủ lôi đình bản nguyên chân thân. Nhờ đó sát lục lôi bị khóa ổn trong chân thân, trở thành lực lượng thuộc về Vương Lâm thay vì bị thiên địa khống chế.","thuocTinh":"Cấm chế, pháp tắc","uyLuc":"Ổn định và hạn chế sát lục lôi trong lôi đình bản nguyên chân thân.","dacDiem":"Hóa thành tấm lưới pháp tắc khi dung hợp với chân thân bản nguyên.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1806","tangDatToi":"Dung hợp vào lôi đình bản nguyên chân thân","trangThai":"đang nắm giữ"}],"congNang":["Hạn chế sát lục lôi trong chân thân lôi đình @c1806"],"tabs":{"tienTrinh":[{"chuong":"@c1806","loai":"xuất hiện","importance":"normal","giaiDoan":"Khóa ổn sát lục lôi","text":"Cấm chế bản nguyên dung hợp vào lôi đình bản nguyên chân thân, hóa thành tấm lưới pháp tắc để ổn định và hạn chế sát lục lôi.","anchor":"Cấm chế bản nguyên là pháp tắc, sau khi dung hợp liền hóa thành một tấm lưới lớn"}]},"capNhatToi":"@c1806","nguon":["@c1806"]},{"id":"sinh-tu-nhan-qua-chan-gia","name":"Sinh tử, nhân quả, chân giả","cn":"","aliases":["Ba hư bản nguyên"],"loai":"khac","loaiLabel":"Ba hư bản nguyên","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sinh tử, nhân quả, chân giả là ba hư bản nguyên cuối cùng mà Vương Lâm chuẩn bị dung hợp. Nếu quy nhất thành công, chín đạo bản nguyên của hắn sẽ còn ba và tu vi có thể tiến tới Không Huyền đại viên mãn.","detail":"Sau khi Vương Lâm đạt Không Huyền hậu kỳ ở chương 1806, ánh mắt hắn chuyển sang ba hư bản nguyên sinh tử, nhân quả, chân giả. Chúng được đặt làm mục tiêu kế tiếp trong tiến trình quy nhất bản nguyên của hắn trước khi nghênh chín lần Huyền Kiếp để hướng tới Không Kiếp.","thuocTinh":"Hư bản nguyên","uyLuc":"Quy nhất ba hư bản nguyên có thể thúc đẩy Vương Lâm tiến tới Không Huyền đại viên mãn.","dacDiem":"Là ba hư bản nguyên cuối trong hệ chín bản nguyên của Vương Lâm.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1806","tangDatToi":"Chuẩn bị dung hợp","trangThai":"đang nắm giữ"}],"congNang":["Quy nhất để đưa chín bản nguyên còn ba và tăng tu vi @c1806"],"tabs":{"tienTrinh":[{"chuong":"@c1806","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu dung hợp kế tiếp","text":"Ba hư bản nguyên sinh tử, nhân quả, chân giả được nêu là mục tiêu dung hợp kế tiếp của Vương Lâm sau khi hắn đạt Không Huyền hậu kỳ.","anchor":"Sinh tử, nhân quả, chân giả!"}]},"capNhatToi":"@c1806","nguon":["@c1806"]},{"id":"ba-dao-hu-ban-nguyen-sinh-tu-nhan-qua-chan-gia","name":"Ba đạo hư bản nguyên sinh tử, nhân quả, chân giả","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Hư bản nguyên / ý cảnh","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ba đạo hư bản nguyên sinh tử, nhân quả, chân giả do ý cảnh của Vương Lâm tự sinh ra trong cơ thể. Khi dung hợp, chúng hóa thành vòng tròn khắc lên trán, mở ra mạch nhập đạo và thúc đẩy tu vi tiến tới Không Huyền đại viên mãn.","detail":"Ba đạo hư bản nguyên này không đến từ ngoại lực mà hình thành qua quá trình hóa phàm và cảm ngộ của Vương Lâm về sinh tử, nhân quả, chân giả. Khi ba hư bản nguyên dung hợp, chúng kết thành vòng tròn khắc lên trán hn, đánh dấu bước nhập đạo. Sự dung hợp này kéo theo khí tức tu vi tăng vọt, đưa Vương Lâm tiến tới cảnh giới Không Huyền đại viên mãn nhờ hòa nhập cùng thiên địa lực.","thuocTinh":"hư bản nguyên, ý cảnh","nguonGoc":"Do ý cảnh của Vương Lâm tự sinh ra trong cơ thể","uyLuc":"Đẩy tu vi Vương Lâm tiến tới Không Huyền đại viên mãn sau khi dung hợp với thiên địa lực.","dacDiem":"Dung hợp thành vòng tròn khắc lên trán Vương Lâm.","congNang":["Dung hợp sinh tử, nhân quả, chân giả thành mạch nhập đạo cho Vương Lâm @c1807","Thúc đẩy khí tức tu vi Vương Lâm tăng vọt sau khi khắc lên trán @c1807"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1807","tangDatToi":"dung hợp ba hư bản nguyên","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1807","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Dung hợp nhập đạo","text":"Ba hư bản nguyên do ý cảnh của Vương Lâm sinh ra được dung hợp thành vòng tròn khắc lên trán, mở ra bước nhập đạo và làm tu vi tăng vọt.","anchor":"Ba đạo bản nguyên này không phải Vương Lâm bằng vào ngoại lực đạt được mà là Ý Cảnh tự sinh ra trong cơ thể"}]},"capNhatToi":"@c1807","nguon":["@c1807"]},{"id":"y-canh-chan-gia","name":"Ý Cảnh chân giả","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Ý cảnh / hư bản nguyên","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ý Cảnh chân giả là bước cảm ngộ sau nhân quả trong chuỗi hư bản nguyên của Vương Lâm. Trong đó hiện lên Tô Đạo và sáu mươi năm trong mộng.","detail":"Ý Cảnh chân giả nối sau nhân quả và dẫn Vương Lâm tới nơi có đạo, tham gia vào vòng dung hợp ba hư bản nguyên.","thuocTinh":"chân giả, hư bản nguyên","congNang":["Giúp Vương Lâm cảm ngộ đạo sau sinh tử và nhân quả @c1807"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1807","tangDatToi":"dung hợp vào ba hư bản nguyên","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1807","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Cảm ngộ đạo","text":"Ý Cảnh chân giả hiện ra cùng Tô Đạo và sáu mươi năm trong mộng, trở thành một phần của ba hư bản nguyên dung hợp.","anchor":"Trong chân giả hắn thấy Tô Đạo, thấy sáu mươi năm trong mộng"}]},"capNhatToi":"@c1807","nguon":["@c1807"]},{"id":"sat-luc-loi-dinh","name":"Sát lục lôi đình","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Lôi đình / thần thông","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Sát lục lôi đình là đạo lôi đình Vương Lâm vô ý sáng tạo. Uy lực hủy diệt của nó rất lớn, đến chính hắn cũng chưa nắm rõ và chưa thể nắm giữ hoàn toàn.","detail":"Sau khi Vương Lâm đạt Không Huyền đại viên mãn và dung hợp chân thân, sát lục lôi đình được nhắc như sức mạnh tiềm tàng vượt ngoài mức chiến lực thông thường của hắn.","thuocTinh":"lôi đình, sát lục","uyLuc":"Lực lượng hủy diệt mạnh đến mức Vương Lâm cũng chưa rõ giới hạn.","dacDiem":"Do Vương Lâm vô ý sáng tạo và chưa nắm giữ hoàn toàn.","congNang":["Tạo lực lượng hủy diệt rất mạnh khi Vương Lâm không tiếc trả giá sử dụng @c1807"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1807","tangDatToi":"chưa nắm giữ hoàn toàn","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1807","loai":"nhắc tới","importance":"normal","giaiDoan":"Chưa nắm giữ","text":"Vương Lâm tự xét sát lục lôi đình là đạo lôi đình do hắn vô ý sáng tạo, có uy lực hủy diệt lớn nhưng chưa thể nắm giữ.","anchor":"Đạo lôi đình đó hắn trong lúc vô ý sáng tạo ra, bản thân cũng không thể nắm giữ"}]},"capNhatToi":"@c1807","nguon":["@c1807"]},{"id":"ngu-hanh-chan-than","name":"Ngũ hành chân thân","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Bản nguyên chân thân","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ngũ hành chân thân là chân thân bản nguyên được Vương Lâm gọi về sau khi đạt Không Huyền đại viên mãn. Khi dung nhập bản thể, nó khiến tu vi trong cơ thể hắn tăng lên mấy lần.","detail":"Chân thân này trở về bản thể cùng lôi đình bản nguyên chân thân, củng cố chiến lực của Vương Lâm trước lúc chờ Huyền Kiếp.","thuocTinh":"ngũ hành, bản nguyên chân thân","congNang":["Dung nhập bản thể để làm tu vi trong cơ thể Vương Lâm tăng lên mấy lần @c1807","Tăng mạnh chiến lực khi Vương Lâm giao chiến với Thiên Tôn @c1830"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1807","tangDatToi":"năm ngũ hành chân thân","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1807","loai":"thi triển","importance":"normal","giaiDoan":"Dung nhập bản thể","text":"Ngũ hành chân thân được Vương Lâm gọi về và dung hợp vào bản thể, khiến tu vi của hắn tăng thêm nhiều lần.","anchor":"Trong nháy mắt khi ngũ hành chân thân dung hợp. Tu vi trong cơ thể Vương Lâm lại tăng lên mấy lần nữa"},{"chuong":"@c1830","loai":"thi triển","importance":"normal","giaiDoan":"Toàn lực luận bàn","text":"Vương Lâm gọi ra năm ngũ hành chân thân trong trận giao thủ toàn lực với lão tổ Thiên Môn.","anchor":"Vương Lâm đứng dậy, bên ngoài thân thể bất ngờ xuất hiện năm ngũ hành chân thân!"}]},"capNhatToi":"@c1807","nguon":["@c1807","@c1830"]},{"id":"ngu-hanh-ban-nguyen","name":"Ngũ hành bản nguyên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Bản nguyên / thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ngũ hành bản nguyên của Vương Lâm tản ra từ thân thể trong lúc đối mặt Tuyết kiếp. Nó tạo hư ảnh để ngũ hành chân thân bước ra ứng kiếp.","detail":"Trong Huyền Kiếp tại Hạt Miếu, Vương Lâm khiến ngũ hành bản nguyên tản ra khỏi thân thể, từ đó ngũ hành chân thân xuất hiện để đối phó đệ nhất kiếp. Biểu hiện lần này cho thấy ngũ hành bản nguyên là nền tảng để hắn tách ra ngũ hành chân thân khi cần ứng chiến với kiếp nạn.","dinhDanh":"goc","thuocTinh":"Ngũ hành","congNang":["Tách ra ngũ hành chân thân để đối phó Tuyết kiếp @c1808"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1808","tangDatToi":"Vận dụng để gọi ngũ hành chân thân","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1808","loai":"thi triển","importance":"normal","giaiDoan":"Đối mặt Tuyết kiếp","text":"Vương Lâm khiến ngũ hành bản nguyên tản ra khỏi thân thể để ngũ hành chân thân bước ra ứng kiếp.","anchor":"Chỉ thấy trong thân thể hắn, ngũ hành bản nguyên bỗng nhiên tán ra"}]},"capNhatToi":"@c1808","nguon":["@c1808"]},{"id":"tuyet-kiep","name":"Tuyết kiếp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Đệ nhất ngoại kiếp","phamCap":"Đệ nhất kiếp của Huyền Kiếp","hePhai":"","soHuu":[],"blurb":"Tuyết kiếp là đệ nhất kiếp của Huyền Kiếp mà Vương Lâm gặp tại Hạt Miếu. Nó hiện thành tuyết trắng, hàn khí và những lưỡi tuyết sắc bén lao vào người độ kiếp.","detail":"Trong lần Huyền Kiếp của Vương Lâm, đệ nhất kiếp hiện ra dưới dạng tuyết trắng phủ trời đất, hàn khí lan rộng rồi hoa tuyết hóa thành những lưỡi tuyết sắc bén từ bốn phương tám hướng đánh tới. Kiếp này bị ngũ hành chân thân của Vương Lâm dùng biển lửa và hỏa long thiêu sụp.","dinhDanh":"goc","thuocTinh":"Hàn tuyết","congNang":["Dùng tuyết trắng, hàn khí và lưỡi tuyết sắc bén công kích người độ kiếp @c1808"],"tabs":{"tienTrinh":[{"chuong":"@c1808","loai":"xuất hiện","importance":"normal","giaiDoan":"Đệ nhất kiếp","text":"Tuyết kiếp giáng xuống thành tuyết trắng và hàn khí, sau đó hóa thành lưỡi tuyết sắc bén công kích Vương Lâm nhưng bị ngũ hành chân thân thiêu sụp.","anchor":"Đệ nhất kiếp của Huyền Kiếp này không ngờ lại là tuyết kiếp!"}]},"capNhatToi":"@c1808","nguon":["@c1808"]},{"id":"chin-con-loc-kiep","name":"Chín cơn lốc kiếp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Kiếp nạn / phong kiếp chưa gọi tên riêng","phamCap":"Một kiếp trong Huyền Kiếp","hePhai":"","soHuu":[],"blurb":"Chín cơn lốc kiếp xuất hiện sau khi Tuyết kiếp sụp đổ. Chúng mang lực giằng xé, lần lượt lao xuống rồi dung hợp bao phủ Vương Lâm và hơn nửa Hạt Miếu.","detail":"Sau đệ nhất kiếp, bầu trời nổi sấm gió và xuất hiện chín cơn lốc kinh thiên. Các cơn lốc mang lực lượng giằng xé, lần lượt lao xuống rồi hợp thành một cơn gió lốc lớn bao vây hơn nửa Hạt Miếu, nhưng không làm Vương Lâm biến sắc.","dinhDanh":"goc","thuocTinh":"Phong kiếp","congNang":["Giằng xé thân thể và bao phủ khu vực rộng quanh Hạt Miếu @c1808"],"tabs":{"tienTrinh":[{"chuong":"@c1808","loai":"xuất hiện","importance":"normal","giaiDoan":"Sau Tuyết kiếp","text":"Chín cơn lốc kinh thiên xuất hiện sau Tuyết kiếp, lần lượt lao xuống rồi dung hợp bao phủ Vương Lâm và hơn nửa Hạt Miếu.","anchor":"đột nhiên xuất hiện chín cơn lốc kinh thiên"}]},"capNhatToi":"@c1808","nguon":["@c1808"]},{"id":"y-chi-cua-loi","name":"Ý chí của lôi","cn":"","aliases":["ý chí lôi đình"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi đình","soHuu":["Vương Lâm"],"blurb":"Ý chí lôi đình từ cơ thể Vương Lâm tuôn ra, đủ sức áp đảo lôi kiếp đang giáng xuống.","detail":"Khi lôi kiếp sắp hạ xuống, Vương Lâm phóng ra ý chí của lôi khiến lôi kiếp run sợ, không tiếp tục đánh vào hắn mà bị cuốn ngược vào kiếp vân.","thuocTinh":"lôi đình","uyLuc":"Có thể khiến lôi kiếp run rẩy và đảo ngược vào kiếp vân.","dacDiem":"Dựa trên địa vị và ý chí lôi đình của Vương Lâm, đối kháng trực diện với lôi kiếp.","congNang":["Áp chế lôi kiếp và khiến lôi kiếp bị cuốn ngược vào kiếp vân @c1809"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1809","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1809","loai":"thi triển","importance":"normal","giaiDoan":"Áp đảo lôi kiếp","text":"Ý chí của lôi từ cơ thể Vương Lâm tuôn ra, áp đảo lôi kiếp đang giáng xuống và khiến nó bị cuốn ngược vào kiếp vân.","anchor":"từ cơ thể Vương Lâm tuôn ra một luồng ý chí của lôi"}]},"capNhatToi":"@c1809","nguon":["@c1809"]},{"id":"loi-dinh-dai-thanh","name":"Lôi đình đại thành","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"đại thành","hePhai":"Lôi đình","soHuu":["Vương Lâm"],"blurb":"Lôi đình đại thành là trạng thái lôi đạo Vương Lâm tự nhận khi đối mặt lôi kiếp.","detail":"Vương Lâm tuyên bố bản thân là lôi đình đại thành, lôi kiếp chỉ có thể do hắn giáng xuống người khác chứ không phải thứ dùng để phạt hắn.","thuocTinh":"lôi đình","uyLuc":"Đủ để đảo ngược thế công của lôi kiếp trong Huyền Kiếp.","dacDiem":"Thể hiện quyền chủ động của Vương Lâm trước lôi kiếp.","congNang":["Khiến Vương Lâm áp đảo lôi kiếp bằng vị thế lôi đình đại thành @c1809"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1809","tangDatToi":"đại thành","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1809","loai":"nhắc tới","importance":"normal","giaiDoan":"Tự nhận lôi đạo","text":"Vương Lâm tự nhận lôi đình đã đại thành, vì vậy lôi kiếp không thể dùng để trừng phạt hắn.","anchor":"Tự ta là lôi đình đại thành, lôi kiếp chỉ có ta giáng xuống người khác!"}]},"capNhatToi":"@c1809","nguon":["@c1809"]},{"id":"tram-ly-kiep","name":"Trảm ly kiếp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Kiếp nạn","phamCap":"Huyền Kiếp nội tam kiếp","hePhai":"Huyền Kiếp","soHuu":[],"blurb":"Trảm ly kiếp là đệ nhất kiếp trong nội tam kiếp của Huyền Kiếp, chuyên nhắm vào mối liên hệ giữa thân thể và hồn phách của người độ kiếp. Kiếp này dùng tiếng trống hạn chế thân thể rồi ngưng vụ kiếm chém xuống dây liên hệ thân-hồn.","detail":"Trảm ly kiếp là kiếp thứ nhất trong nội tam kiếp thuộc Huyền Kiếp. Khi kiếp phát động, một chiếc trống khổng lồ vang lên, tiếng trống khiến thân thể người độ kiếp tạm thời không nhúc nhích. Tiếp đó, sương mù ngưng tụ thành vụ kiếm mang sát khí chém thẳng vào liên hệ giữa thân thể với hồn phách, không trực tiếp tấn công thân thể, Nguyên Thần hay hồn phách. Vương Lâm đã phá kiếp này bằng tâm động lôi âm và âm đao.","thuocTinh":"kiếp nạn, thân hồn, sát khí","nguonGoc":"Nội tam kiếp của Huyền Kiếp","uyLuc":"Có thể khiến thân thể người độ kiếp tạm thời không nhúc nhích và dùng vụ kiếm chém vào liên hệ giữa thân thể với hồn phách.","dacDiem":"Không trực tiếp chém thân thể, Nguyên Thần hay hồn phách, mà nhắm vào dây liên hệ giữa thân thể và hồn phách.","congNang":["Dùng tiếng trống khiến thân thể người độ kiếp tạm thời bất động @c1809","Ngưng vụ kiếm chém vào mối liên hệ giữa thân thể và hồn phách @c1809"],"tabs":{"tienTrinh":[{"chuong":"@c1809","loai":"xuất hiện","importance":"major","giaiDoan":"Đệ nhất nội kiếp","text":"Trảm ly kiếp xuất hiện như đệ nhất kiếp trong nội tam kiếp, dùng tiếng trống và vụ kiếm nhằm cắt đứt liên hệ thân-hồn của Vương Lâm trước khi bị phá vỡ.","anchor":"Đây là đệ nhất kiếp trong nội tam kiếp, trảm ly kiếp!"}]},"capNhatToi":"@c1809","nguon":["@c1809"]},{"id":"noi-tam-kiep","name":"Nội tam kiếp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Giai đoạn kiếp nạn","phamCap":"Huyền Kiếp","hePhai":"Huyền Kiếp","soHuu":[],"blurb":"Nội tam kiếp là giai đoạn kiếp nạn bên trong thuộc Huyền Kiếp, mở ra sau khi ba lần kiếp đầu đã tan nát, được dẫn động bởi chiếc trống khổng lồ xuất hiện trên bầu trời.","detail":"Sau khi người độ kiếp vượt qua ba kiếp đầu của Huyền Kiếp, chiếc trống ngàn trượng hiện ra trên không trung, báo hiệu Huyền Kiếp chuyển sang tầng kiếp nạn nguy hiểm hơn — nội tam kiếp. Giai đoạn này gồm ba kiếp bên trong, trong đó kiếp thứ nhất là trảm ly kiếp, tấn công trực tiếp vào liên hệ giữa thân thể, Nguyên Thần và hồn phách của người độ kiếp.","thuocTinh":"kiếp nạn","nguonGoc":"Huyền Kiếp","dacDiem":"Được dẫn động bởi chiếc trống khổng lồ, mở ra sau khi ba lần Huyền Kiếp đầu đã tan nát.","congNang":["Mở giai đoạn kiếp nạn bên trong sau khi ba kiếp đầu của Huyền Kiếp tan nát, trong đó trảm ly kiếp là đệ nhất kiếp @c1809"],"cacTang":[{"ten":"Trảm ly kiếp","moTa":"Đệ nhất kiếp trong nội tam kiếp, dùng tiếng trống và vụ kiếm chém liên hệ thân-hồn.","chuong":"@c1809"}],"tabs":{"tienTrinh":[{"chuong":"@c1809","loai":"xuất hiện","importance":"major","giaiDoan":"Mở nội tam kiếp","text":"Nội tam kiếp bắt đầu khi chiếc trống khổng lồ hiện ra, đánh dấu Huyền Kiếp chuyển sang tầng kiếp nạn nguy hiểm hơn.","anchor":"Chiếc trống khổng lồ kia là mấu chốt dẫn dắt kiếp này, vừa xuất hiện là chứng tỏ nội tam kiếp đã bắt đầu triển khai!"}]},"capNhatToi":"@c1809","nguon":["@c1809"]},{"id":"huyet-anh-kiep","name":"Huyết ảnh kiếp","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Huyền Kiếp / nội tam kiếp","phamCap":"Đệ nhị kiếp trong nội tam kiếp","hePhai":"Huyền Kiếp","soHuu":[],"blurb":"Huyết ảnh kiếp là đệ nhị kiếp trong nội tam kiếp, hóa ra vô số huyết ảnh giáp đỏ bất tử bất diệt. Mỗi huyết ảnh có tu vi không kém Không Huyền và càng bị đánh tan càng mạnh hơn.","detail":"Trong Huyền Kiếp của Vương Lâm, huyết ảnh kiếp hiện ra từ kiếp vân bằng vô số huyết ảnh mặc giáp đỏ. Các huyết ảnh không kém Không Huyền, bị đánh tan sẽ ngưng tụ lại và mỗi lần chết tu vi lại tăng, nhưng lần này bị kim quang cùng thiên uy trong hai mắt Vương Lâm trấn áp đến phải rút lui.","congNang":["Tạo vô số huyết ảnh giáp đỏ có tu vi không kém Không Huyền, bất tử bất diệt và càng chết càng mạnh @c1810"],"uyLuc":"Có thể khiến người độ kiếp rơi vào vòng giao chiến càng đánh càng bất lợi, nhưng bị ánh mắt thiên uy của Vương Lâm ép lui trong chương này.","dacDiem":"Thuộc nội tam kiếp của Huyền Kiếp, thiên về huyết ảnh bất diệt và tích lũy sức mạnh sau mỗi lần bị diệt.","tabs":{"tienTrinh":[{"chuong":"@c1810","loai":"xuất hiện","importance":"normal","giaiDoan":"Đệ nhị kiếp nội tam kiếp","text":"Huyết ảnh kiếp hiện ra bằng vô số huyết ảnh giáp đỏ bất tử bất diệt, nhưng bị ánh mắt thiên uy của Vương Lâm trấn áp đến rút về kiếp vân.","anchor":"Mỗi một huyết ảnh này đều có tu vi không kém Không Huyền, lại bất tử bất diệt"}]},"capNhatToi":"@c1810","nguon":["@c1810"]},{"id":"thap-tuc-kho-than-kiep","name":"Thập tức khô thần kiếp","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Huyền Kiếp / hồn tam kiếp","phamCap":"Đệ nhất kiếp trong hồn tam kiếp","hePhai":"Huyền Kiếp","soHuu":[],"blurb":"Thập tức khô thần kiếp là kiếp thứ bảy trong Huyền Kiếp và là đệ nhất kiếp của hồn tam kiếp. Kiếp này giết người bằng cách làm Nguyên Thần khô héo trong thời gian cực ngắn.","detail":"Khi kiếp vân tiêu tán, u quang ngưng thành ấn ký mặt quỷ trên trời, khiến Nguyên Thần trong cơ thể Vương Lâm nhanh chóng khô héo. Kiếp này vô hình khó phá, quyền lực Đạo Cổ xuyên qua ấn ký mà không gây tổn thương, đồng thời uy áp Huyền Kiếp phong tỏa thiên địa lực xung quanh khiến người độ kiếp khó tự bổ sung.","congNang":["Làm Nguyên Thần tu sĩ khô héo trong bảy nhịp thở, dẫn tới hình thần câu diệt @c1810","Ấn ký kiếp khó bị công kích trực tiếp, quyền lực Đạo Cổ xuyên qua mà không gây thương tổn @c1810"],"uyLuc":"Trực tiếp nhắm vào Nguyên Thần, khiến Vương Lâm trong một nhịp thở đã khô héo gần một phần tư Nguyên Thần.","dacDiem":"Thuộc hồn tam kiếp, khác với nội tam kiếp trước đó ở chỗ tấn công sâu vào Nguyên Thần và phong tỏa khả năng hút thiên địa lực từ bên ngoài.","tabs":{"tienTrinh":[{"chuong":"@c1810","loai":"xuất hiện","importance":"normal","giaiDoan":"Đệ nhất kiếp hồn tam kiếp","text":"Thập tức khô thần kiếp mở ra bằng ấn ký mặt quỷ trên trời, khiến Nguyên Thần Vương Lâm khô héo rất nhanh và buộc hắn phải tìm nguồn thiên địa lực khác để tự cứu.","anchor":"Nguyên Thần trong thời gian bảy nhịp thở khô héo mà chết"}]},"capNhatToi":"@c1810","nguon":["@c1810"]},{"id":"khong-kiep","name":"Không Kiếp","cn":"","loai":"khac","loaiLabel":"Cảnh giới","phamCap":"Đại cảnh giới sau Không Huyền","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Không Kiếp là cảnh giới Vương Lâm đạt được sau khi phá xong Huyền Kiếp thứ chín,ính thức bước vào Không Kiếp sơ kỳ.","detail":"Sau khi ấn ký Luân hồi kiếp tan vỡ, khí tức Không Kiếp từ bụi đất bùng lên làm trời cao biến sắc. Uy áp được xác nhận là Không Kiếp sơ kỳ, đánh dấu Vương Lâm vượt qua ngưỡng Không Huyền. Đây là mốc tu luyện xuất hiện tại @c1811.","tabs":{"tienTrinh":[{"chuong":"@c1811","loai":"xuất hiện","importance":"major","giaiDoan":"Không Kiếp sơ kỳ","text":"Vương Lâm phá xong kiếp cuối và bước vào Không Kiếp sơ kỳ.","anchor":"Tuy chỉ là uy áp của Không Kiếp sơ kỳ"}]},"nguon":["@c1811"],"uyLuc":"Khí tức Không Kiếp bùng phát từ bụi đất khiến trời cao biến sắc,uy áp đạt tầng Không Kiếp sơ kỳ @c1811."},{"id":"thap-tuc-tho-hon-kiep","name":"Thập tức thọ hồn kiếp","cn":"","loai":"khac","loaiLabel":"Huyền Kiếp thứ tám","phamCap":"Hồn tam kiếp","hePhai":"","soHuu":[],"blurb":"Thập tức thọ hồn kiếp là kiếp thứ tám trong Huyền Kiếp, thuộc hồn tam kiếp. Kiếp này buộc người độ kiếp tự hiến tế hồn thọ — mỗi nhịp thở tương đương một ngàn năm — để quyết định độ khó của kiếp thứ chín.","detail":"Thập tức thọ hồn kiếp không trực tiếp tấn công Nguyên Thần mà đặt người độ kiếp trước lựa chọn hiến tế thọ nguyên. Hiến càng nhiều nhịp thở thì kiếp thứ chín càng dễ vượt, ngược lại hiến ít thì kiếp cuối sẽ khó hơn bội phần. Vương Lâm khi đối diện kiếp này chỉ tế hiến một năm rồi chủ động tiến vào kiếp thứ chín, thể hiện tâm tính cương quyết không chịu khuất phục trước áp lực của Huyền Kiếp.","congNang":["Ép người độ kiếp hiến tế hồn thọ, mỗi nhịp thở đổi một ngàn năm thọ nguyên @c1811","Lượng hiến tế quyết định trực tiếp độ khó của kiếp thứ chín @c1811"],"tabs":{"tienTrinh":[{"chuong":"@c1811","loai":"xuất hiện","importance":"major","giaiDoan":"Huyền Kiếp thứ tám","text":"Kiếp thứ tám hé lộ quy tắc hiến tế hồn thọ và bị Vương Lâm vượt qua bằng cách chỉ tế hiến một năm.","anchor":"Thập tức thọ hồn kiếp, kiếp nạn thứ hai trong hồn tam kiếp"}]},"nguon":["@c1811"],"dacDiem":"Không trực tiếp hủy hoại Nguyên Thần mà dùng cơ chế lựa chọn — ép người độ kiếp tự cắt thọ nguyên để đổi lấy kiếp sau nhẹ hơn."},{"id":"luan-hoi-kiep","name":"Luân hồi kiếp","cn":"","loai":"khac","loaiLabel":"Huyền Kiếp thứ chín","phamCap":"Kiếp cuối của Huyền Kiếp","hePhai":"","soHuu":[],"blurb":"Luân hồi kiếp là Huyền Kiếp thứ chín, ấn ký cuối cùng mang thiên uy luân hồi, đóng vai trò hố sâu ngăn cách tu sĩ bước vào cảnh giới Đại Tôn Không Kiếp. Vương Lâm không chịu độ kiếp theo lối thường mà dùng ngũ tiễn hóa ngũ trường long phá nát ấn ký này.","detail":"Luân hồi kiếp là ấn ký cuối trong chín Huyền Kiếp, chứa thiên uy luân hồi, vốn là ranh giới cực hiểm dành cho tu sĩ muốn đột phá thành Đại Tôn Không Kiếp.hi kiếp giáng xuống, người độ kiếp sẽ chìm vào luân hồi, khiến việc vượt kiếp trở nên gần như bất khả. Tại thời điểm đối mặt ấn ký này, Vương Lâm đã dùng cung Lý Quảng phối hợp ngũ hành chân thân cùng lôi đình bản nguyên chân thân bắn ra năm mũi tên hóa thành năm trường long, phá nát Luân hồi kiếp thay vì chấp nhận độ kiếp theo lối thường.","congNang":["Khiến người độ kiếp chìm vào luân hồi, trở thành hố sâu ngăn cách tu sĩ bước vào cảnh giới Đại Tôn Không Kiếp @c1811"],"tabs":{"tienTrinh":[{"chuong":"@c1811","loai":"xuất hiện","importance":"major","giaiDoan":"Huyền Kiếp thứ chín","text":"Luân hồi kiếp xuất hiện như ấn ký cuối và bị Vương Lâm dùng ngũ long phá nát.","anchor":"Kiếp này tên là luân hồi, là hố sâu ngăn cách tu sĩ trở thành Đại Tôn Không Kiếp"}]},"nguon":["@c1811"]},{"id":"tin-niem-cua-vuong-lam","name":"Tín niệm của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Tín niệm","phamCap":"Gần tín thuật Đại Thiên Tôn","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Tín niệm của Vương Lâm giúp một tia Nguyên Thần không tan trong Khô thần kiếp. Khi dùng để công kích Huyền Kiếp, nó được mô tả là rất gần tín thuật của Đại Thiên Tôn.","detail":"Trong lúc Nguyên Thần gần như khô héo, phần còn lại của Vương Lâm hóa thành tín niệm bất khuất gắn với con đường tu đạo và khát vọng hồi sinh Lý Mộ Uyển. Tín niệm ấy không bị thiên uy xóa đi, giúp hắn phản kích ấn ký kiếp thứ bảy và tiếp tục phá kiếp cuối.","congNang":["Giữ lại một tia Nguyên Thần không bị Khô thần kiếp xóa bỏ @c1811","Khi công kích Huyền Kiếp, thần thông dưới tín niệm này gần với tín thuật Đại Thiên Tôn @c1811"],"tabs":{"tienTrinh":[{"chuong":"@c1811","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng Huyền Kiếp","text":"Tín niệm giúp Vương Lâm giữ Nguyên Thần và công kích ấn ký Huyền Kiếp.","anchor":"Dưới tín niệm này, thần thông của hắn đã vô cùng gần với tín thuật của Đại Thiên Tôn"}]},"nguon":["@c1811"]},{"id":"phong-an-bon-ky-hieu-cua-tien-to","name":"Phong ấn bốn ký hiệu của Tiên Tổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông phong ấn","phamCap":"không rõ","hePhai":"Tiên Tổ","soHuu":["Tiên Tổ"],"blurb":"Phong ấn gồm bốn ký hiệu màu đỏ do Tiên Tổ để lại trên Lục Ma Hạt Hồn. Nó trấn áp hồn phách này và từng hóa giải một quyền chứa lực lượng Đạo Cổ cùng tu vi Không Kiếp của Vương Lâm.","detail":"Bốn ký hiệu đỏ nằm ở đầu, đuôi, phía trước và phía sau thân hình Lục Ma Hạt Hồn. Khi Vương Lâm đánh một quyền vào Hạt Hồn, phong ấn lóe lên để triệt tiêu lực lượng công kích; sau khi Thiên Nghịch Châu hấp thu Hạt Hồn, các ký hiệu mất đối tượng trấn áp rồi hóa thành tro bụi.","thuocTinh":"phong ấn trấn áp","uyLuc":"Có thể hóa giải một quyền dung hợp lực lượng Đạo Cổ và toàn bộ tu vi Không Kiếp sơ kỳ của Vương Lâm.","dacDiem":"Biểu hiện thành bốn ấn ký đỏ đặt ở bốn vị trí trên thân Lục Ma Hạt Hồn.","congNang":["Trấn áp Lục Ma Hạt Hồn dưới đáy Hạt Miếu.","Triệt tiêu lực lượng công kích đánh vào Hạt Hồn khi phong ấn còn hiệu lực."],"trangThai":"tiêu tán","capNhatToi":"@c1812","tabs":{"tienTrinh":[{"chuong":"@c1812","loai":"xuất hiện","importance":"normal","giaiDoan":"hiện trên Lục Ma Hạt Hồn","text":"Bốn ký hiệu đỏ trên thân Lục Ma Hạt Hồn hiện ra, hóa giải một quyền của Vương Lâm rồi tan biến sau khi Hạt Hồn bị Thiên Nghịch Châu hấp thu.","anchor":"Trên thân thể nó có bốn ấn ký màu đỏ, phong ấn ở đầu đuôi và phía trước phía sau thân hình"}]},"nguon":["@c1812"]},{"id":"me-vu-dai-tran-ho-son-dao-ma-tong","name":"Mê vụ đại trận hộ sơn Đạo Ma Tông","aliases":["Đạo Ma mê vụ trận","Mê vụ đại trận","Hộ sơn đại trận Đạo Ma Tông","Đạo Ma mê vụ trận"],"cn":"","loai":"khac","loaiLabel":"Trận pháp hộ tông","phamCap":"không rõ","hePhai":"Đạo Ma Tông","soHuu":["Đạo Ma Tông"],"blurb":"Trận pháp hộ tông bao phủ Đạo Ma Tông trong hơn trăm năm. Trận được duy trì khi số lượng môn nhân giảm mạnh vì viễn chinh.","detail":"Đạo Ma Tông mở trận này để thủ hộ tông môn và phòng ngừa biến cố trong thời gian phần lớn môn nhân đi viễn chinh, khiến cả khu vực bị mê vụ bao phủ.","congNang":["Bao phủ và thủ hộ Đạo Ma Tông trong thời gian môn nhân giảm mạnh @c1814"],"trangThai":"đang mở","capNhatToi":"@c1814","tabs":{"tienTrinh":[{"chuong":"@c1814","loai":"xuất hiện","importance":"normal","giaiDoan":"Hộ tông hơn trăm năm","text":"Đạo Ma Tông duy trì Đạo Ma mê vụ trận hơn trăm năm để thủ hộ tông môn khi số lượng tu sĩ còn lại giảm mạnh.","anchor":"Đạo Ma Tông bởi vì ít đi đại bộ phân tu sĩ, trong hơn trăm năm nay vẫn luôn mở Đạo Ma mê vụ trận"}]},"nguon":["@c1814"]},{"id":"phong-toa-hoa-long-loi-dien-cam-che-cua-vuong-lam","name":"Phong tỏa hỏa long-lôi điện-cấm chế của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông/trận phong ấn tạm thời","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Phong tỏa do Vương Lâm lập quanh Đạo Ma Tông trước khi bước vào trả thù. Nó kết hợp hỏa long, lưới sét và cấm chế để trấn áp khu vực tông môn.","detail":"Vương Lâm vung tay tạo biển lửa hóa chín mươi chín hỏa long, dẫn sấm sét thành lưới điện rồi khuếch tán cấm chế để liên kết lửa và sét, hình thành một phong ấn trấn áp Đạo Ma Tông.","thuocTinh":"hỏa, lôi, cấm chế","uyLuc":"Có thể phong tỏa và trấn áp khu vực Đạo Ma Tông trước khi Vương Lâm bước vào sát phạt.","dacDiem":"Dùng nhiều loại lực lượng cùng lúc, lấy cấm chế làm lớp liên kết giữa hỏa diễm và sấm sét.","congNang":["Phong tỏa, liên kết hỏa diễm và sấm sét bằng cấm chế để trấn áp Đạo Ma Tông @c1814"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1814","tangDatToi":"thi triển được","trangThai":"đang dùng"}],"capNhatToi":"@c1814","tabs":{"tienTrinh":[{"chuong":"@c1814","loai":"thi triển","importance":"normal","giaiDoan":"Phong tỏa Đạo Ma Tông","text":"Vương Lâm dùng biển lửa hóa hỏa long, dung nhập sấm sét và khuếch tán cấm chế để lập phong tỏa trấn áp Đạo Ma Tông.","anchor":"Sau sấm sét là một vùng lớn cấm chế khuếch tán ra, khiến cho hỏa diễm và sấm sét liên kết với nhau"}]},"nguon":["@c1814"]},{"id":"bat-dao-tram-than-hon-thuat","name":"Bát đao trảm thân hồn thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Ngưu Châu","soHuu":["Vân Dật Phong"],"blurb":"Thần thông làm nên thanh danh của Vân Dật Phong trong trăm năm đại chiến hai châu.","detail":"Bát đao trảm thân hồn thuật được nhắc là thuật pháp trong tay Vân Dật Phong có thanh danh hiển hách, khiến hắn trở thành tu sĩ hàng đầu của Thiên Ngưu Châu trong chiến tranh.","nguon":["@c1816"],"nguoiTu":[{"ten":"Vân Dật Phong","tuChuong":"@c1816","tangDatToi":"mức nổi danh trong chiến tranh","trangThai":"đang tu"}],"congNang":["Tạo nên uy danh sát phạt của Vân Dật Phong trong chiến tranh hai châu @c1816"],"tabs":{"tienTrinh":[{"chuong":"@c1816","loai":"nhắc tới","importance":"normal","giaiDoan":"Nổi danh chiến trường","text":"Bát đao trảm thân hồn thuật được nêu là thuật pháp khiến Vân Dật Phong thanh danh hiển hách trong đại chiến.","anchor":"Bát đao trảm thân hồn thuật trong tay hắn thanh danh hiển hách!"}]},"capNhatToi":"@c1816"},{"id":"kim-cuong-dao","name":"Kim cương đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Đạo Ma Tông","soHuu":["Lão già kim bào"],"blurb":"Thần thông phòng hộ do lão già kim bào thi triển khi tử chiến với Vương Lâm.","detail":"Kim cương đạo khiến kim quang bao phủ thân thể lão già kim bào và hiện ra kim thân trang nghiêm để chống đỡ thế công của Vương Lâm.","nguon":["@c1816"],"thuocTinh":"kim quang phòng hộ","nguoiTu":[{"ten":"Lão già kim bào","tuChuong":"@c1816","tangDatToi":"thi triển trong tử chiến","trangThai":"đã thi triển"}],"congNang":["Tạo kim quang bao phủ toàn thân và kim thân phòng hộ @c1816"],"tabs":{"tienTrinh":[{"chuong":"@c1816","loai":"thi triển","importance":"normal","giaiDoan":"Kim thân phòng hộ","text":"Lão già kim bào thi triển Kim cương đạo để kim quang bao phủ toàn thân khi đối đầu Vương Lâm.","anchor":"Cùng với tiếng rống của hắn, một vùng kim quang bất ngờ bao phủ toàn thân hắn."}]},"capNhatToi":"@c1816"},{"id":"dai-luc-ma","name":"Đại lực ma","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Đạo Ma Tông","soHuu":["Lão già kim bào"],"blurb":"Thần thông hóa ma tôn khổng lồ do lão già kim bào thi triển sau Kim cương đạo.","detail":"Đại lực ma biến hắc khí quanh lão già kim bào thành ma tôn khổng lồ mặc giáp, dùng để công thủ trước Vương Lâm nhưng bị cốt đao chém tan.","nguon":["@c1816"],"thuocTinh":"ma khí","nguoiTu":[{"ten":"Lão già kim bào","tuChuong":"@c1816","tangDatToi":"thi triển trong tử chiến","trangThai":"đã thi triển"}],"congNang":["Hóa hắc khí thành ma tôn khổng lồ mặc giáp để công thủ @c1816"],"tabs":{"tienTrinh":[{"chuong":"@c1816","loai":"thi triển","importance":"normal","giaiDoan":"Ma tôn hiện hình","text":"Lão già kim bào thi triển Đại lực ma, hắc khí hóa thành ma tôn khổng lồ nghênh kích Vương Lâm.","anchor":"bất ngờ hóa thành một ma tôn khổng lồ"}]},"capNhatToi":"@c1816"},{"id":"chuong-an-chin-ngon","name":"Chưởng ấn chín ngón","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Chưởng ấn khổng lồ chín ngón do Vương Lâm thi triển trong trận Đạo Ma Tông.","detail":"Vương Lâm vỗ trời tạo chưởng ấn khổng lồ có chín ngón tay, phối hợp thêm chưởng ấn từ ngũ hành chân thân và lôi đình bản nguyên chân thân, ép nam tử hồng bào phải hóa hồng vụ thành hai cánh tay khổng lồ chống đỡ.","nguon":["@c1816"],"thuocTinh":"chưởng ấn khổng lồ","uyLuc":"Bóng chưởng che phủ hơn nửa Đạo Ma Tông.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1816","tangDatToi":"thi triển trong trận Đạo Ma Tông","trangThai":"đã thi triển"}],"congNang":["Tạo chưởng ấn khổng lồ có chín ngón, che phủ hơn nửa Đạo Ma Tông @c1816"],"tabs":{"tienTrinh":[{"chuong":"@c1816","loai":"thi triển","importance":"normal","giaiDoan":"Chưởng phủ Đạo Ma","text":"Vương Lâm thi triển chưởng ấn chín ngón, cùng hai chân thân tạo thêm chưởng ấn đánh xuống nam tử hồng bào và bao phủ Đạo Ma Tông.","anchor":"Chưởng ấn này không ngờ lại có chín ngón tay!"}]},"capNhatToi":"@c1816"},{"id":"dao-ma-huyet-than","name":"Đạo Ma huyết thân","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đạo Ma Tông","soHuu":["Nam tử mặc hồng bào của Đạo Ma Tông"],"blurb":"Thần thông huyết thân đạo-ma do nam tử mặc hồng bào thi triển để chống chưởng ấn của Vương Lâm.","detail":"Người thi triển phun máu, khiến máu toàn thân bao phủ và hình thành huyết thân; trong công kích, tay trái ẩn đạo, tay phải ngưng ma để đánh nát chưởng ấn đầu tiên của Vương Lâm.","congNang":["Tạo huyết thân mang khí tức đạo-ma để công kích và đối kháng chưởng ấn @c1817"],"nguoiTu":[{"ten":"Nam tử mặc hồng bào của Đạo Ma Tông","tuChuong":"@c1817","tangDatToi":"Đã thi triển","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1817","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng chưởng ấn đầu tiên","text":"Nam tử mặc hồng bào thi triển Đạo Ma huyết thân, dùng đạo và ma trong song chưởng đánh nát chưởng ấn đầu tiên của Vương Lâm.","anchor":"bất ngờ hình thành một khối huyết thân"}]},"capNhatToi":"@c1817","nguon":["@c1817"]},{"id":"than-thong-don-huyet-nhuc-vao-song-chuong","name":"Thần thông dồn huyết nhục vào song chưởng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Nam tử mặc hồng bào của Đạo Ma Tông","Đầu to"],"blurb":"Thần thông dồn tinh hoa huyết nhục vào hai tay để tăng uy lực song chưởng trong lúc nguy cấp.","detail":"Nam tử mặc hồng bào khiến hai chân và thân thể khô héo, toàn bộ huyết nhục tụ vào song chưởng nhằm chống chưởng ấn thứ hai của Vương Lâm. Chương đối chiếu loại thần thông này với thứ Vương Lâm từng thấy trên người Đầu to, nhưng thủ đoạn của nam tử hồng bào kém xa về độ tinh diệu.","congNang":["Dồn huyết nhục toàn thân vào song chưởng để tăng uy lực đối kháng @c1817"],"nguoiTu":[{"ten":"Nam tử mặc hồng bào của Đạo Ma Tông","tuChuong":"@c1817","tangDatToi":"Đã thi triển","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1817","loai":"thi triển","importance":"normal","giaiDoan":"Chống chưởng ấn thứ hai","text":"Nam tử mặc hồng bào dồn toàn bộ huyết nhục vào song chưởng để phá chưởng ấn thứ hai, nhưng phải trả giá bằng cánh tay trái nổ tung.","anchor":"toàn bộ huyết nhục đều ngưng tụ lại tại song chưởng"}]},"capNhatToi":"@c1817","nguon":["@c1817"]},{"id":"thieu-dot-linh-hon-va-tinh-mang-doi-tu-vi-kim-ton","name":"Thiêu đốt linh hồn và tính mạng đổi tu vi Kim Tôn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Đạo Ma Tông","soHuu":["Nam tử mặc hồng bào của Đạo Ma Tông"],"blurb":"Bí thuật liều mạng tạm kéo tu vi lên Kim Tôn trong mười nhịp thở.","detail":"Trong tuyệt cảnh, nam tử mặc hồng bào thiêu đốt linh hồn và tính mạng để đổi lấy tu vi bạo tăng, từ Đại Tôn Không Kiếp tạm vọt tới trình độ Kim Tôn. Cái giá của bí thuật là sinh mạng, dù hết mười nhịp thở hay không thì hắn cũng phải chết.","congNang":["Tạm tăng cảnh giới từ Đại Tôn Không Kiếp lên Kim Tôn trong mười nhịp thở @c1817"],"dacDiem":"Đại giá là sinh mạng của người thi triển.","nguoiTu":[{"ten":"Nam tử mặc hồng bào của Đạo Ma Tông","tuChuong":"@c1817","tangDatToi":"Tạm đạt Kim Tôn","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1817","loai":"thi triển","importance":"normal","giaiDoan":"Tạm đạt Kim Tôn","text":"Nam tử mặc hồng bào thiêu đốt linh hồn và tính mạng để tạm tăng tu vi lên Kim Tôn trong mười nhịp thở.","anchor":"đối lấy việc tu vi bạo tăng trong nháy mắt"}]},"capNhatToi":"@c1817","nguon":["@c1817"]},{"id":"tran-phap-phong-an-dao-ma-tong","name":"Trận pháp phong ấn Đạo Ma Tông","cn":"","loai":"than-thong","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Trận pháp phong ấn bốn phía Đạo Ma Tông, được Vương Lâm dùng trong cuộc diệt môn.","detail":"Trận pháp hình tròn bao kín Đạo Ma Tông, khiến tu sĩ bỏ chạy không thoát. Khi bắt đầu chuyển động và co rút, nó chạm tới tu sĩ thì khiến họ tử vong, đồng thời nghiền phá kiến trúc tông môn.","congNang":["Phong tỏa phạm vi Đạo Ma Tông, co rút để diệt sát tu sĩ và phá hủy kiến trúc @c1817"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1817","tangDatToi":"Đã bố trí và kích hoạt","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1817","loai":"thi triển","importance":"normal","giaiDoan":"Diệt môn Đạo Ma Tông","text":"Vương Lâm kích hoạt trận pháp phong ấn khiến tu sĩ Đạo Ma Tông bỏ chạy bị bao vây và chết khi trận pháp co rút.","anchor":"cấm chế trận pháp hình tròn này bắt đầu chuyển động"}]},"capNhatToi":"@c1817","nguon":["@c1817"]},{"id":"cam-che-phong-an-dao-ma-tong","name":"Cấm chế phong ấn Đạo Ma Tông","cn":"","loai":"khac","loaiLabel":"Cấm chế / trận pháp phong ấn","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cấm chế phong ấn bao quanh Đạo Ma Tông rồi nhanh chóng co rút, phá hủy tông môn và sát thương tu sĩ hàng loạt. Sau đó nó tiếp tục ép vào hồ nước trung tâm để buộc Hải Long hiện thân.","detail":"Tại Lục Ma Châu, cấm chế phong ấn quanh Đạo Ma Tông co lại trong thời gian rất ngắn, phá sập kiến trúc, giết gần ba vạn tu sĩ và chỉ giữ lại mấy chục Nguyên Thần toàn năng để Vương Lâm thu lấy. Khi Vương Lâm chuyển mục tiêu sang hồ trung tâm, cấm chế tiếp tục co vào hồ, làm nước hồ tan rã và ép thủ hộ tiên thú Hải Long lao ra.","congNang":["Phá hủy kiến trúc và diệt sát tu sĩ trong phạm vi Đạo Ma Tông @c1818","Bắt giữ mấy chục Nguyên Thần toàn năng để Vương Lâm thu lấy @c1818","Co vào hồ trung tâm để ép Hải Long thủ hộ hiện thân @c1818"],"uyLuc":"Có thể tàn phá Đạo Ma Tông trong chưa tới ba mươi nhịp thở và khiến toàn môn gần như diệt vong.","dacDiem":"Dạng cấm chế hình tròn co rút từ bốn phía, càng thu hẹp càng nghiền ép mục tiêu trong phạm vi phong tỏa.","trangThai":"đang vận hành","capNhatToi":"@c1818","tabs":{"tienTrinh":[{"chuong":"@c1818","loai":"thi triển","importance":"normal","giaiDoan":"Hủy tông và ép thủ hộ thú","text":"Cấm chế phong ấn quanh Đạo Ma Tông co rút, phá hủy tông môn, giết tu sĩ, gom Nguyên Thần toàn năng và tiếp tục ép vào hồ để buộc Hải Long hiện thân.","anchor":"Trên Lục Ma Châu. Đạo Ma Tông giờ phút này bị cấm chế phong ấn bốn phía nhanh chóng co rút lại."}]},"nguon":["@c1818"]},{"id":"hu-anh-dao-ma","name":"Hư ảnh đạo ma","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đạo Ma Tông","soHuu":["Tông chủ Đạo Ma Tông"],"blurb":"Thần thông phòng ngự do Tông chủ Đạo Ma Tông vận chuyển tu vi hóa ra để chống lại Vương Lâm.","detail":"Hai hư ảnh đạo ma xuất hiện quanh người Tông chủ Đạo Ma Tông khi hắn liều mạng chống cự quyền của Vương Lâm, nhưng vẫn bị đánh nát trong trận truy sát trước thánh chỉ.","congNang":["Hóa hai hư ảnh đạo ma quanh người để chống cự công kích @c1820"],"tabs":{"tienTrinh":[{"chuong":"@c1820","loai":"thi triển","importance":"normal","giaiDoan":"Tông chủ Đạo Ma Tông chống quyền của Vương Lâm","text":"Tông chủ Đạo Ma Tông hóa ra hai hư ảnh đạo ma quanh người để liều mạng chống lại Vương Lâm nhưng bị phá tan.","anchor":"bất ngờ hóa thành hai hư ảnh đạo ma"}]},"nguon":["@c1820"]},{"id":"loi-cau-ho-than-cua-tong-chu-dao-ma-tong","name":"Lôi cầu hộ thân của Tông chủ Đạo Ma Tông","cn":"","loai":"than-thong","loaiLabel":"Thần thông lôi","phamCap":"Không rõ","hePhai":"Đạo Ma Tông","soHuu":["Tông chủ Đạo Ma Tông"],"blurb":"Thủ đoạn lôi đình của Tông chủ Đạo Ma Tông khi bị Vương Lâm truy sát.","detail":"Tông chủ Đạo Ma Tông phóng lượng lớn sét ngưng thành vô số lôi cầu bay về phía Vương Lâm nhằm ngăn địch, nhưng quyền thứ ba của Vương Lâm phá tan toàn bộ.","congNang":["Ngưng sét thành vô số lôi cầu lao vào đối thủ để công kích và ngăn cản @c1820"],"tabs":{"tienTrinh":[{"chuong":"@c1820","loai":"thi triển","importance":"normal","giaiDoan":"Tông chủ Đạo Ma Tông trọng thương phản kích","text":"Tông chủ Đạo Ma Tông hóa sét thành vô số lôi cầu lao về phía Vương Lâm nhưng bị phá tan.","anchor":"hóa thành vô số lôi cầu bay về phía Vương Lâm"}]},"nguon":["@c1820"]},{"id":"con-loc-mau-den-cua-vuong-lam","name":"Cơn lốc màu đen của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông do Vương Lâm vận chuyển tu vi toàn thân tạo thành cơn lốc đen phá pháp bảo.","detail":"Vương Lâm vung tay áo, khiến cơn lốc màu đen từ cơ thể khuếch tán ra và va chạm với chín thanh phi đao màu đen của Tông chủ Đạo Ma Tông, phá nát toàn bộ.","congNang":["Khuếch tán thành cơn lốc đen để phá nát phi đao tấn công @c1820"],"tabs":{"tienTrinh":[{"chuong":"@c1820","loai":"thi triển","importance":"normal","giaiDoan":"Phá chín phi đao màu đen","text":"Vương Lâm tạo cơn lốc đen từ cơ thể khuếch tán ra và phá nát chín phi đao màu đen.","anchor":"Một cơn lốc màu đen từ trong cơ thể hắn khuếch tán ra"}]},"nguon":["@c1820"]},{"id":"can-nuot-nguyen-than","name":"Cắn nuốt Nguyên Thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông hút nuốt Nguyên Thần được Vương Lâm dùng để kết liễu Tông chủ Đạo Ma Tông.","detail":"Vương Lâm há miệng hút mạnh về phía Nguyên Thần Tông chủ Đạo Ma Tông đang bỏ chạy, tạo lực hút khiến đối phương không thoát được và cuối cùng bị cắn nuốt.","congNang":["Tạo lực hút kéo Nguyên Thần bỏ chạy về phía người thi triển để cắn nuốt @c1820"],"tabs":{"tienTrinh":[{"chuong":"@c1820","loai":"thi triển","importance":"normal","giaiDoan":"Nuốt Nguyên Thần Tông chủ","text":"Vương Lâm hút mạnh về phía Nguyên Thần Tông chủ Đạo Ma Tông, khiến đối phương hóa u quang bị cắn nuốt.","anchor":"hướng về phía Tông chủ Đạo Ma Tông đang bỏ chạy hút mạnh một cái"}]},"nguon":["@c1820"]},{"id":"anh-mat-tran-ap-chua-manh-vo-tien-cuc-kiem","name":"Ánh mắt trấn áp chứa mảnh vỡ Tiên Cực Kiếm","cn":"","loai":"than-thong","loaiLabel":"Thần thông uy áp","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Uy áp từ hai mắt Vương Lâm, trong kim quang ẩn chứa mảnh vỡ Tiên Cực Kiếm.","detail":"Khi sứ giả hoàng tộc dùng kim ấn ngăn cản, hai mắt Vương Lâm bùng kim quang có mảnh vỡ Tiên Cực Kiếm và lực trấn áp thiên địa, khiến kim ấn dừng lại và làm sứ giả phải lui.","congNang":["Dùng kim quang trong mắt chứa mảnh vỡ Tiên Cực Kiếm để trấn áp kim ấn và uy hiếp sứ giả hoàng tộc @c1820"],"tabs":{"tienTrinh":[{"chuong":"@c1820","loai":"thi triển","importance":"normal","giaiDoan":"Trấn áp kim ấn","text":"Vương Lâm dùng ánh mắt chứa mảnh vỡ Tiên Cực Kiếm làm kim ấn dừng lại và khiến sứ giả hoàng tộc run sợ.","anchor":"Trong kim quang này ẩn chứa mảnh vỡ của Tiên Cực Kiếm"}]},"nguon":["@c1820"]},{"id":"truyen-tong-tran-tu-thanh-chi","name":"Truyền Tống Trận từ thánh chỉ","cn":"","loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"không rõ","hePhai":"Hoàng tộc Tiên Tộc","soHuu":["Sứ giả hoàng tộc","Vương Lâm"],"blurb":"Công năng truyền tống ẩn trong thánh chỉ của Tiên Hoàng. Sứ giả hoàng tộc nói có thể dùng nó làm Truyền Tống Trận để tới Trung Châu.","detail":"Thánh chỉ do sứ giả hoàng tộc trao cho Vương Lâm không chỉ là chiếu chỉ mà còn có thể dùng làm Truyền Tống Trận. Từ Lục Ma Châu tới Trung Châu cần truyền tống tám lần, cho thấy công năng này phục vụ di chuyển đường xa.","dinhDanh":"goc","congNang":["Dùng thánh chỉ làm Truyền Tống Trận để truyền tống đường xa tới Trung Châu @c1821"],"nguoiTu":[{"ten":"Sứ giả hoàng tộc","tuChuong":"@c1821","tangDatToi":"sử dụng","trangThai":"đã biết cách dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1821","loai":"xuất hiện","importance":"normal","giaiDoan":"được sứ giả giải thích","text":"Sứ giả hoàng tộc nói thánh chỉ có thể dùng làm Truyền Tống Trận và từ Lục Ma Châu tới Trung Châu cần tám lần truyền tống.","anchor":"thánh chỉ này có thể dùng làm Truyền Tống Trận"}]},"capNhatToi":"@c1821","nguon":["@c1821"]},{"id":"bat-cuc-dao","name":"Bát Cực đạo","cn":"","loai":"cong-phap","loaiLabel":"truyền thừa đạo pháp","phamCap":"Đại Thiên Tôn truyền thừa","hePhai":"Tiên Tộc","soHuu":["Tiên Hoàng"],"blurb":"Đạo pháp được Liên Vân Quyết lưu lại trong Thiên Tôn Niết, có nguồn gốc truyền thừa từ Thái Cổ thần cảnh. (+) Bát Cực đạo là truyền thừa của Tiên Hoàng ở Trung Châu, gắn với danh hiệu Bát Cực Đại Thiên Tôn. [CAN-SOAT-GOP] (+) Đạo thuật Tiên Hoàng gọi tên khi vỗ xuống đầu lâu Tiên Tổ, dùng để kích phát lực lượng đầu lâu trong trận chiến với các Đại Thiên Tôn. [CAN-SOAT-GOP]","detail":"Chương này nêu Tiên Hoàng ở Trung Châu truyền thừa Tiên Tổ Bát Cực đạo, là một trong ngũ đại tuyệt thế cường giả của bảy mươi hai châu Tiên Tộc.","nguoiTu":[{"ten":"Tiên Hoàng","tuChuong":"@c1822","tangDatToi":"Bát Cực Đại Thiên Tôn","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1822","loai":"xuất hiện","importance":"normal","giaiDoan":"được giới thiệu cùng Tiên Hoàng","text":"Bát Cực đạo được nêu là truyền thừa của Tiên Hoàng ở Trung Châu.","anchor":"Tiên Hoàng ở Trung Châu truyền thừa Tiên Tổ Bát Cực đạo"}]},"capNhatToi":"@c1822","nguon":["@c1822","@c1856","@c1890"]},{"id":"than-the-chinh-la-dao","name":"Thân thể chính là đạo","cn":"","loai":"than-thong","loaiLabel":"Đạo pháp / cảnh giới vận dụng","phamCap":"Thiên Tôn","hePhai":"Thiên Tôn","soHuu":["Lão tổ Đạo Ma Tông"],"blurb":"Cách vận dụng đạo ở cấp Thiên Tôn, khi đạo niệm và ý chí dung nhập vào thân thể khiến nhục thân tự thân là đạo. Lão tổ Đạo Ma Tông thể hiện cảnh giới này qua quyền đầu tiên khiến thiên địa biến sắc.","detail":"Quyền đầu của lão tổ Đạo Ma Tông cho thấy cấp Thiên Tôn không cần tách rời thần thông khỏi thân thể như tu sĩ thông thường. Khi đạo niệm và ý chí hòa vào thân thể, nhục thân trở thành đạo, khiến nắm tay cũng là đạo và đòn đánh có thể kéo theo thiên địa lực, không gian cùng nhiều lớp thần thông. Một quyền tung ra khiến thiên địa biến sắc, không gian như độc lập và hút thiên địa lực.","thuocTinh":"đạo niệm dung thân","uyLuc":"Một quyền của Thiên Tôn khiến thiên địa biến sắc, không gian như độc lập và hút thiên địa lực.","dacDiem":"Nhục thân là trung tâm vận đạo, quyền cước tự mang đại đạo.","congNang":["Dung đạo niệm và ý chí vào thân thể, khiến quyền cước mang đại đạo và thần thông @c1823"],"nguoiTu":[{"ten":"Lão tổ Đạo Ma Tông","tuChuong":"@c1823","tangDatToi":"Thiên Tôn vận dụng","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1823","loai":"thi triển","importance":"major","giaiDoan":"Quyền đầu của Thiên Tôn","text":"Lão tổ Đạo Ma Tông tung quyền đầu thể hiện cảnh giới thân thể là đạo, khiến nắm tay mang đại đạo và chín loại thần thông.","anchor":"Đây là nhờ có việc khiến đạo niệm bản thân, ý chí bản thân hoàn toàn dung nhập vào đạo bên trong thân thể"}]},"capNhatToi":"@c1823","nguon":["@c1823"]},{"id":"quyen-thu-hai-cua-lao-to-dao-ma-tong","name":"Quyền thứ hai của lão tổ Đạo Ma Tông","cn":"","loai":"than-thong","loaiLabel":"Thần thông Thiên Tôn","phamCap":"Thiên Tôn","hePhai":"Đạo Ma Tông","soHuu":["Lão tổ Thiên Tôn của Đạo Ma Tông"],"blurb":"Một quyền chứa mười tám loại thần thông, mở vùng hư vô đen tối quanh Vương Lâm.","detail":"Quyền thứ hai của lão tổ Đạo Ma Tông thể hiện cách chiến đấu cấp Thiên Tôn: nhiều đạo và thần thông dung vào quyền cước. Khi đánh ra, thiên địa quanh Vương Lâm hóa thành vùng hư vô đen tối, khiến Kim Tôn bình thường gần như không có tư cách chống cự.","uyLuc":"Mở hư vô đen tối và áp chế cấp Kim Tôn.","dacDiem":"Một quyền ẩn chứa mười tám loại thần thông.","congNang":["Tạo vùng hư vô vô biên vô hạn quanh mục tiêu @c1824"],"nguoiTu":[{"ten":"Lão tổ Thiên Tôn của Đạo Ma Tông","tuChuong":"@c1824","tangDatToi":"Thiên Tôn","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1824","loai":"thi triển","importance":"normal","giaiDoan":"Đối chiến Vương Lâm","text":"Lão tổ Đạo Ma Tông thi triển quyền thứ hai, mở vùng hư vô đen tối quanh Vương Lâm và ép hắn phải dùng thân Đạo Cổ cùng ý chí để chống lại.","anchor":"Đây là một vùng hư vô vô biên vô hạn, không gian đen tối"}]},"capNhatToi":"@c1824","nguon":["@c1824"]},{"id":"quyen-thu-ba-cua-lao-to-dao-ma-tong","name":"Quyền thứ ba của lão tổ Đạo Ma Tông","cn":"","loai":"than-thong","loaiLabel":"Thần thông Thiên Tôn","phamCap":"Thiên Tôn","hePhai":"Đạo Ma Tông","soHuu":["Lão tổ Thiên Tôn của Đạo Ma Tông"],"blurb":"Một kích toàn lực của lão tổ Đạo Ma Tông, chứa hai mươi bảy đạo biến hóa và tạo thành hắc động cắn nuốt thiên địa.","detail":"Quyền thứ ba là đòn toàn lực mà lão tổ Đạo Ma Tông dùng để kết thúc nhân quả Đạo Ma Tông. Nắm tay chứa hai mươi bảy đạo biến hóa, hình thành hắc động lớn giữa hai người, cắn nuốt phế tích, bầu trời và mặt đất rồi lao về phía Vương Lâm.","uyLuc":"Tạo hắc động cắn nuốt tất cả khí tức, phế tích, thiên không và mặt đất.","dacDiem":"Một kích toàn lực chứa hai mươi bảy loại biến hóa.","congNang":["Tạo hắc động lớn cắn nuốt khí tức và vật thể xung quanh @c1824"],"nguoiTu":[{"ten":"Lão tổ Thiên Tôn của Đạo Ma Tông","tuChuong":"@c1824","tangDatToi":"Thiên Tôn","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1824","loai":"thi triển","importance":"normal","giaiDoan":"Một kích toàn lực","text":"Lão tổ Đạo Ma Tông tung quyền thứ ba, tạo thành hắc động lớn cắn nuốt phế tích Đạo Ma Tông, thiên không và mặt đất rồi lao vào Vương Lâm.","anchor":"nắm tay ẩn chứa hai mươi bảy loại biến háo, bất ngờ khiến không gian giữa hắn và Vương Lâm hình thành một hắc động lớn"}]},"capNhatToi":"@c1824","nguon":["@c1824"]},{"id":"thien-nguu-hon-luc","name":"Thiên Ngưu Hồn lực","cn":"","loai":"bi-thuat","loaiLabel":"Hồn lực gia trì","phamCap":"Không rõ","hePhai":"Thiên Ngưu Châu","soHuu":["Thiên Ngưu Hồn","Vương Lâm"],"blurb":"Hồn lực của Thiên Ngưu Hồn được Vương Lâm mượn để tạm nâng tu vi tới trình độ Kim Tôn.","detail":"Khi ấn ký Thiên Ngưu Hồn lan khắp thân thể Vương Lâm, hồn lực tiến vào huyết nhục, Nguyên Thần và linh hồn hắn. Lực gia trì này khiến tu vi Vương Lâm từ Không Kiếp sơ kỳ liên tục tăng tới Không Kiếp trung kỳ, Không Kiếp hậu kỳ đỉnh phong rồi tạm dừng ở trình độ Kim Tôn.","thuocTinh":"Hồn lực gia trì","uyLuc":"Tạm nâng tu vi người được tán thành cao độ tới trình độ Kim Tôn.","dacDiem":"Gắn với mức tán thành cao độ của Thiên Ngưu Hồn.","congNang":["Tạm nâng tu vi của Vương Lâm từ Không Kiếp sơ kỳ lên trình độ Kim Tôn @c1824"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1824","tangDatToi":"Mượn lực tới Kim Tôn","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1824","loai":"xuất hiện","importance":"normal","giaiDoan":"Mượn hồn lực","text":"Vương Lâm kích hoạt ấn ký Thiên Ngưu Hồn, mượn hồn lực khiến tu vi tăng vọt tới trình độ Kim Tôn.","anchor":"Mượn hồn lực lên tới Kim Tôn"}]},"capNhatToi":"@c1824","nguon":["@c1824"]},{"id":"thien-nguu-chang","name":"Thiên Ngưu Chàng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Thiên Ngưu","soHuu":["Vương Lâm"],"blurb":"Thiên Ngưu Chàng là thần thông có nguồn gốc từ ký ức Thiên Ngưu, được Vương Lâm thi triển khi mượn Thiên Ngưu Hồn lực. Khi chín mươi tám thân ảnh đồng loạt phát động, uy lực đủ phá hắc động chứa hai mươi bảy thần thông của lão tổ Thiên Tôn Đạo Ma Tông.","detail":"Vương Lâm lấy chiêu thức này từ ký ức của Thiên Ngưu, thi triển bằng cách hóa chín mươi tám thân ảnh đồng loạt gọi ra hư ảnh Thiên Ngưu màu xanh húc về phía đối phương. Trong trận chiến với lão tổ Thiên Tôn của Đạo Ma Tông, chín mươi tám đạo hợp công đã phá vỡ hắc động chứa hai mươi bảy thần thông và ép đối phương bị thương.","nguonGoc":"Ký ức Thiên Ngưu","uyLuc":"Chín mươi tám đạo hợp công có thể phá hắc động hai mươi bảy thần thông và ép Thiên Tôn bị thương.","congNang":["Gọi ra hư ảnh Thiên Ngưu màu xanh để húc phá thần thông đối phương @c1825","Khi do chín mươi tám thân ảnh cùng thi triển, uy lực đủ phá hắc động chứa hai mươi bảy thần thông của lão tổ Thiên Tôn @c1825"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1825","tangDatToi":"Thi triển hoàn mỹ bằng chín mươi tám thân ảnh","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1825","loai":"thi triển","importance":"major","giaiDoan":"Chín mươi tám đạo hợp công","text":"Vương Lâm dùng Thiên Ngưu Chàng lấy từ ký ức Thiên Ngưu, hóa chín mươi tám thân ảnh cùng gọi hư ảnh Thiên Ngưu để phá hắc động của lão tổ Thiên Tôn của Đạo Ma Tông.","anchor":"Hắn liên tục thi triển chín mươi tám loại thần thông sau khi tu vi mượn Thiên Ngưu Hồn lực đề cao, lấy được trong ký ức của Thiên Ngưu - Thiên Ngưu Chàng!"}]},"capNhatToi":"@c1825"},{"id":"dung-dao-vao-than-the","name":"Dung đạo vào thân thể","cn":"","loai":"bi-thuat","loaiLabel":"Phương thức dung hợp thần thông","phamCap":"Thiên Tôn","hePhai":"","soHuu":["Lão tổ Thiên Tôn của Đạo Ma Tông"],"blurb":"Phương thức dung nhiều thần thông vào thân thể hoặc đòn đánh, giúp một quyền một cước chứa uy lực của nhiều đạo thần thông.","detail":"Thiên Tôn có thể dung nhiều đạo thần thông vào một quyền một cước; lão tổ Thiên Tôn của Đạo Ma Tông đạt mức hai mươi bảy đạo, còn cực hạn Thiên Tôn được nêu là chín mươi chín đạo trước ngưỡng Dược Thiên Tôn.","uyLuc":"Một quyền dung hợp hai mươi bảy đạo thần thông đã là chiến lực Thiên Tôn rất mạnh; cực hạn Thiên Tôn là chín mươi chín đạo.","congNang":["Dung nhiều đạo thần thông vào thân thể hoặc đòn đánh để tăng uy lực trực tiếp @c1825"],"tabs":{"tienTrinh":[{"chuong":"@c1825","loai":"xuất hiện","importance":"normal","giaiDoan":"Hai mươi bảy đạo thần thông","text":"Chương giải thích cơ chế dung đạo vào thân thể qua lão tổ Thiên Tôn của Đạo Ma Tông, người có thể dung hợp hai mươi bảy loại thần thông vào một quyền.","anchor":"Giống như lão tổ Thiên Tôn của Đạo Ma Tông, có thể dung hợp hai mươi bảy loại thần thông vào trong một quyền"}]},"capNhatToi":"@c1825","nguon":["@c1825"]},{"id":"hac-dong-cua-lao-to-dao-ma-tong","name":"Hắc động của lão tổ Đạo Ma Tông","cn":"","loai":"than-thong","loaiLabel":"Thần thông chiến đấu","phamCap":"Thiên Tôn","hePhai":"Đạo Ma Tông","soHuu":["Lão tổ Thiên Tôn của Đạo Ma Tông"],"blurb":"Thần thông hắc động chứa hai mươi bảy đạo thần thông của lão tổ Thiên Tôn của Đạo Ma Tông.","detail":"Hắc động này mang hai mươi bảy thứ thần thông, từng làm sụp đổ gần bốn mươi đạo thần thông trong hư ảnh Thiên Ngưu nhưng cuối cùng bị Thiên Ngưu Chàng của Vương Lâm va nát.","uyLuc":"Chứa hai mươi bảy thần thông trong một đòn hắc động.","congNang":["Tạo hắc động chứa hai mươi bảy đạo thần thông để nghiền ép đối thủ @c1825"],"nguoiTu":[{"ten":"Lão tổ Thiên Tôn của Đạo Ma Tông","tuChuong":"@c1825","tangDatToi":"Dung hai mươi bảy đạo thần thông","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1825","loai":"thi triển","importance":"normal","giaiDoan":"Đối chiến Thiên Ngưu Chàng","text":"Lão tổ Thiên Tôn của Đạo Ma Tông dùng hắc động chứa hai mươi bảy thần thông đối chiến Vương Lâm, nhưng hắc động bị Thiên Ngưu Chàng va nát.","anchor":"Hai mươi bảy thứ thần thông chứa trong hắc động kia sau cú va chạm này liền ầm ầm sụp đổ."}]},"capNhatToi":"@c1825","nguon":["@c1825"]},{"id":"mot-quyen-cua-dai-thien-ton","name":"Một quyền của Đại Thiên Tôn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Lực lượng Đại Thiên Tôn","hePhai":"Đạo Nhất Đại Thiên Tôn","soHuu":["Đạo Nhất Đại Thiên Tôn"],"blurb":"Một quyền do thần niệm Đạo Nhất Đại Thiên Tôn thể hiện, trở thành trọng tâm cảm ngộ của Vương Lâm sau trận Đạo Ma Tông. Vương Lâm mô phỏng hơn trăm vạn lần vẫn không tìm được cách chống cự.","detail":"Một quyền này thể hiện chênh lệch cực lớn giữa Vương Lâm và Đại Thiên Tôn. Trong một năm bế quan ở phế tích Đạo Ma Tông, Vương Lâm liên tục tính toán cách ứng đối nhưng vẫn nhận ra mình chưa thể chống lại lực lượng cấp Đại Thiên Tôn.","thuocTinh":"Lực lượng Đại Thiên Tôn","uyLuc":"Vương Lâm dùng mọi phương pháp mô phỏng hơn trăm vạn lần vẫn không tìm ra cách chống cự.","dacDiem":"Được Vương Lâm dùng làm trọng tâm cảm ngộ sau khi chứng kiến thần niệm Đạo Nhất ra tay.","congNang":["Thể hiện uy áp và sức mạnh vượt xa tầng Thiên Tôn mà Vương Lâm hiện có thể chống đỡ @c1826"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1826","tangDatToi":"cảm ngộ","trangThai":"đang-cảm-ngộ"}],"tabs":{"tienTrinh":[{"chuong":"@c1826","loai":"thi triển","importance":"normal","giaiDoan":"Đạo Nhất hiện thần niệm","text":"Một quyền của Đại Thiên Tôn khiến Vương Lâm lấy làm trọng tâm suy diễn trong một năm nhưng vẫn không tìm được phương pháp chống cự.","anchor":"Một quyền nọ ta dùng tất cả mọi phương pháp, không ngừng tính toán trong đầu không dưới trăm vạn lần"}]},"capNhatToi":"@c1826","nguon":["@c1826"]},{"id":"mot-quyen-dung-nhap-than-thong-cua-vuong-lam","name":"Một quyền dung nhập thần thông của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Chiến pháp dung nhập nhiều đạo thần thông vào một quyền của Vương Lâm. Sau ba năm cảm ngộ, hắn xác định khi không mặc Hồn Khải và còn ở Không Kiếp sơ kỳ, một quyền hiện tối đa dung nhập chín đạo thần thông.","detail":"Vương Lâm dùng chiến pháp này làm thước đo chiến lực sau trận Đạo Ma Tông. Giới hạn hiện tại đến từ tu vi Không Kiếp sơ kỳ, nhưng uy lực một quyền đã mạnh hơn trước và khiến hắn tự tin hơn khi đối chiếu với quyền đầu của lão tổ Thiên Tôn Đạo Ma Tông.","dinhDanh":"goc","thuocTinh":"dung nhập thần thông","uyLuc":"Khi không mặc Hồn Khải, giới hạn hiện tại của Vương Lâm là chín đạo thần thông trong một quyền.","dacDiem":"Uy lực chịu hạn chế bởi tu vi thực tế của người thi triển.","congNang":["Dung nhập nhiều đạo thần thông vào một quyền để tăng uy lực công kích @c1827"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1827","tangDatToi":"một quyền dung nhập tối đa chín đạo thần thông khi không mặc Hồn Khải","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1827","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"sau ba năm cảm ngộ","text":"Vương Lâm xác định giới hạn một quyền hiện tại là chín đạo thần thông khi không mặc Hồn Khải.","anchor":"Tu vi thực tế của ta là Không Kiếp sơ kỳ, cũng bởi vì hạn chế này mà một quyền nhiều nhất chỉ dung nhập được chín đạo thần thông."}]},"capNhatToi":"@c1827","nguon":["@c1827"]},{"id":"co-che-thien-ton-niet","name":"Thiên Tôn Niết","cn":"","aliases":[],"loai":"khac","loaiLabel":"Nơi thí luyện","phamCap":"Không rõ","hePhai":"Tiên Tộc","soHuu":[],"blurb":"Nơi thí luyện dành cho tầng cấp Thiên Tôn mà Vương Lâm quyết tâm phải tới. Hắn muốn dùng nơi này để kiểm chứng bản thân có thể xông qua mấy tầng.","detail":"Vương Lâm xem Thiên Tôn Niết là mục tiêu kế tiếp sau khi tổng kết chiến lực và nhu cầu giao chiến với Thiên Tôn. Chương này chưa mô tả cấu trúc cụ thể của nơi thí luyện, chỉ nêu quyết tâm tiến vào để kiểm nghiệm tu vi.","dinhDanh":"goc","congNang":["Dùng làm nơi thí luyện và kiểm nghiệm chiến lực của tu sĩ cấp Thiên Tôn hoặc người muốn đối chiếu với tầng cấp này @c1827"],"tabs":{"tienTrinh":[{"chuong":"@c1827","loai":"nhắc tới","importance":"normal","giaiDoan":"mục tiêu kế tiếp của Vương Lâm","text":"Vương Lâm quyết định nhất định phải tới Thiên Tôn Niết để xem tu vi của mình có thể xông qua mấy tầng.","anchor":"Nơi thí luyện Thiên Tôn Niết này ta nhất định phải tới, xem thử tu vi của ta có thể xông qua được mấy tầng!"}]},"capNhatToi":"@c1827","nguon":["@c1827"]},{"id":"than-niem-thien-ton-cua-vuong-lam","name":"Thần niệm Thiên Tôn của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thiên Tôn","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần niệm uy áp của Vương Lâm có thể truyền vào tâm thần tu sĩ trong một tông môn, khiến người tu vi càng cao càng cảm nhận rõ chấn động.","detail":"Tại Địa Môn, Vương Lâm dùng thần niệm truyền vào tâm thần toàn bộ tu sĩ trong tông môn. Uy áp này không nhằm làm khó tu sĩ cấp thấp nhưng khiến Tông chủ Địa Môn và lão tổ Kim Tôn Trịnh Thiên Lâm bị chấn động mạnh, buộc họ phải ra ngoài nghênh tiếp.","thuocTinh":"thần niệm uy áp","uyLuc":"Áp chế và chấn động tu sĩ cấp cao trong Địa Môn.","dacDiem":"Người có tu vi càng cao càng cảm nhận rõ uy áp.","congNang":["Truyền vào tâm thần tu sĩ toàn tông, tạo uy áp khiến cấp cao phải ra mặt @c1828"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1828","tangDatToi":"Thiên Tôn","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1828","loai":"thi triển","importance":"normal","giaiDoan":"Chấn động Địa Môn","text":"Vương Lâm dùng thần niệm truyền vào tâm thần tu sĩ Địa Môn, khiến tu sĩ cấp cao chịu áp lực mạnh và buộc lão tổ Kim Tôn cùng Tông chủ Địa Môn ra nghênh tiếp.","anchor":"Nhưng dù là như thế nhưng thần niệm của hắn truyền vào trong tâm thần của tất cả tu sĩ trong tông môn này"}]},"capNhatToi":"@c1828","nguon":["@c1828"]},{"id":"bao-tuyet-chin-dao-than-thong-cua-lao-to-thien-mon","name":"Bão tuyết chín đạo thần thông của lão tổ Thiên Môn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Môn","soHuu":["Mộ Dung đạo hữu"],"blurb":"Thần thông do lão tổ Thiên Môn thi triển trong trận luận bàn với Vương Lâm tại Thiên Phong.","detail":"Lão tổ Thiên Môn vung tay khiến tuyết trên Thiên Phong hóa thành bão tuyết, bên trong ẩn chứa chín đạo thần thông nhằm bao phủ Vương Lâm.","thuocTinh":"tuyết","uyLuc":"Tạo bão tuyết công kích diện rộng, ẩn chứa chín đạo thần thông.","dacDiem":"Dùng tuyết trên Thiên Phong làm thế công bao phủ đối thủ.","congNang":["Công kích diện rộng bằng bão tuyết ẩn chứa chín đạo thần thông @c1830"],"nguoiTu":[{"ten":"Mộ Dung đạo hữu","tuChuong":"@c1830","tangDatToi":"chín đạo thần thông","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1830","loai":"thi triển","importance":"normal","giaiDoan":"Luận bàn Thiên Phong","text":"Lão tổ Thiên Môn hóa tuyết thành bão tuyết chứa chín đạo thần thông để công kích Vương Lâm.","anchor":"Trong bão tuyết này có ẩn chứa chín đạo thần thông, giờ phút này gào thét mang theo một tia cuồng bạo"}]},"capNhatToi":"@c1830","nguon":["@c1830"]},{"id":"luc-luong-thien-ton-dung-hop-muoi-bay-dao-than-thong","name":"Lực lượng Thiên Tôn dung hợp mười bảy đạo thần thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông chiến lực","phamCap":"Thiên Tôn","hePhai":"Thiên Môn","soHuu":["Mộ Dung đạo hữu"],"blurb":"Lực lượng Thiên Tôn mà lão tổ Thiên Môn bộc phát trong giai đoạn toàn lực luận bàn với Vương Lâm.","detail":"Khi hai bên toàn lực giao thủ, lão tổ Thiên Môn bộc phát lực lượng Thiên Tôn đã dung hợp mười bảy đạo thần thông.","uyLuc":"Đại diện cho chiến lực Thiên Tôn đã dung hợp mười bảy đạo thần thông.","dacDiem":"Được bộc phát trong trận luận bàn mười ngày với Vương Lâm.","congNang":["Bộc phát chiến lực Thiên Tôn dung hợp mười bảy đạo thần thông @c1830"],"nguoiTu":[{"ten":"Mộ Dung đạo hữu","tuChuong":"@c1830","tangDatToi":"mười bảy đạo thần thông","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1830","loai":"thi triển","importance":"normal","giaiDoan":"Toàn lực luận bàn","text":"Lão tổ Thiên Môn bộc phát lực lượng Thiên Tôn dung hợp mười bảy đạo thần thông khi giao thủ toàn lực với Vương Lâm.","anchor":"bộc phát lực lượng của Thiên Tôn dung hợp mười bảy đạo thần thông!"}]},"capNhatToi":"@c1830","nguon":["@c1830"]},{"id":"dung-hop-bay-muoi-dao-than-thong-vao-mot-chi","name":"Dung hợp bảy mươi đạo thần thông vào một chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông chiến đấu","phamCap":"Thiên Tôn","hePhai":"","soHuu":["Hải Tử Thiên Tôn"],"blurb":"Năng lực chiến đấu của Hải Tử Thiên Tôn, dung hợp bảy mươi đạo thần thông vào một chỉ. Đây là nguyên nhân khiến Vương Lâm thua trận khi không mặc Hồn Khải.","detail":"Hải Tử Thiên Tôn đã có thể dung hợp bảy mươi đạo thần thông vào một chỉ, vượt xa trạng thái chiến đấu hiện tại của Vương Lâm khi chỉ dựa vào phân thân và thần thông thông thường.","nguoiTu":[{"ten":"Hải Tử Thiên Tôn","tuChuong":"@c1831","tangDatToi":"dung hợp bảy mươi đạo","trangThai":"dang-tu"}],"congNang":["Dung hợp bảy mươi đạo thần thông vào một chỉ để tạo ra uy lực vượt trội trong Thiên Tôn chiến @c1831"],"tabs":{"tienTrinh":[{"chuong":"@c1831","loai":"xuất hiện","importance":"normal","giaiDoan":"Hải Tử áp đảo Vương Lâm","text":"Năng lực dung hợp bảy mươi đạo thần thông vào một chỉ của Hải Tử Thiên Tôn được nêu ra như giới hạn khiến Vương Lâm không phải đối thủ nếu không mặc Hồn Khải.","anchor":"Hải Tử Thiên Tôn kia đã có thể dung hợp bảy mươi đạo thần thông vào trong một chỉ"}]},"nguon":["@c1831"]},{"id":"ap-suc-chin-dao-than-thong-ba-lan","name":"Áp súc chín đạo thần thông ba lần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thiên Tôn","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Phương thức chiến đấu của Vương Lâm nhờ hai phân thân phối hợp. Nó giúp hắn áp súc chín đạo thần thông ba lần, đạt hiệu quả ba mươi sáu đạo thần thông.","detail":"Vương Lâm tính toán rằng khi hai phân thân xuất hiện, hắn có thể áp súc chín đạo thần thông tới ba lần. Hiệu quả sau áp súc tương đương ba mươi sáu đạo thần thông, nhưng vẫn chưa đủ thắng Hải Tử Thiên Tôn.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1831","tangDatToi":"áp súc ba lần","trangThai":"dang-tu"}],"congNang":["Áp súc chín đạo thần thông tới ba lần để đạt hiệu quả ba mươi sáu đạo thần thông @c1831"],"tabs":{"tienTrinh":[{"chuong":"@c1831","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Vương Lâm tổng kết chiến lực","text":"Vương Lâm tự tính hai phân thân giúp hắn áp súc chín đạo thần thông tới ba lần và đạt hiệu quả ba mươi sáu đạo.","anchor":"hai phân thân của ta sau khi xuất hiện có thể khiến ta áp súc chín đạo thần thông tới ba lần"}]},"nguon":["@c1831"]},{"id":"dung-muoi-tam-dao-than-thong-vao-mot-quyen","name":"Dung mười tám đạo thần thông vào một quyền","cn":"","loai":"than-thong","loaiLabel":"Thần thông chiến đấu","phamCap":"dự tính Thiên Tôn","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Mục tiêu chiến lực Vương Lâm dự tính sau khi ngũ hành chân thân hoàn toàn dung hợp. Khi đó bản thể có thể dung mười tám đạo thần thông vào một quyền và áp súc tới hiệu quả bảy mươi hai đạo.","detail":"Sau khi gom đủ kim, mộc bản nguyên và hoàn thiện ngũ hành chân thân, Vương Lâm dự tính bản thể sẽ dung được mười tám đạo thần thông vào một quyền. Nhờ áp súc, uy lực có thể đạt hiệu quả bảy mươi hai đạo, đủ để đấu Hải Tử Thiên Tôn.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1831","tangDatToi":"mục tiêu dự tính","trangThai":"du-kien"}],"congNang":["Dung mười tám đạo thần thông vào một quyền, dự tính áp súc tới hiệu quả bảy mươi hai đạo @c1831"],"tabs":{"tienTrinh":[{"chuong":"@c1831","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Mục tiêu sau ngũ hành dung hợp","text":"Vương Lâm xác định nếu ngũ hành chân thân hoàn toàn dung hợp thì bản thể có thể dung mười tám đạo thần thông vào một quyền.","anchor":"Bản thể của ta có thể dung mười tám đạo thần thông vào một quyền"}]},"nguon":["@c1831"]},{"id":"moc-ban-nguyen-chan-than","name":"Mộc bản nguyên chân thân","cn":"","loai":"khac","loaiLabel":"Bản nguyên chân thân","phamCap":"bản nguyên","hePhai":"Mộc","soHuu":["Vương Lâm"],"blurb":"Mộc bản nguyên chân thân là mục tiêu ngưng tụ kế tiếp của Vương Lâm. Sơn Hải Thụ chứa mộc bản nguyên lực có thể giúp hắn trực tiếp hóa thành chân thân này.","detail":"Vương Lâm biết Sơn Hải Thụ ở đáy Sơn Hải còn thân thể chứa mộc bản nguyên lực. Nếu hấp thu được, hắn có thể ngưng tụ mộc bản nguyên và trực tiếp hóa thành chân thân, bổ sung mảnh ghép còn thiếu cho ngũ hành chân thân.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1831","tangDatToi":"chưa ngưng tụ","trangThai":"du-kien"}],"congNang":["Ngưng tụ mộc bản nguyên thành chân thân để tiến tới hoàn thiện ngũ hành chân thân @c1831"],"tabs":{"tienTrinh":[{"chuong":"@c1831","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu Sơn Hải Thụ","text":"Vương Lâm xác định mộc bản nguyên trong Sơn Hải Thụ có thể giúp hắn ngưng tụ mộc bản nguyên và trực tiếp hóa thành chân thân.","anchor":"có thể giúp ta ngưng tụ ra mộc bản nguyên, đồng thời trực tiếp hóa thành chân thân"}]},"nguon":["@c1831"]}]};